module.exports = /*#__PURE__*/JSON.parse('{"탑":[{"name":"Garen","koreanName":"가렌","imageId":"Garen","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"가렌은 불굴의 선봉대를 이끄는 고결하고 자긍심 강한 전사다. 선봉대 내에서 인망이 두터울 뿐 아니라 심지어 적에게도 존경을 받지만, 그가 대대로 데마시아와 데마시아의 이상을 수호하는 임무를 맡은 크라운가드 가문의 자손이기 때문은 아니다. 가렌은 마법 저항력을 갖춘 방어구와 거대한 대검으로 무장하고, 언제라도 마법사에 맞서 정당한 검으로 진정한 칼바람을 일으킬 준비가 되어 있다.","tags":["전사","탱커","입문추천"]},{"name":"Gangplank","koreanName":"갱플랭크","imageId":"Gangplank","positions":["탑"],"riotClass":"전사","riotSubClass":null,"difficulty":"어려움","style":["전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"몰락한 해적왕 갱플랭크는 잔인한 성격에다 종잡을 수 없으며 사악함은 타의 추종을 불허한다. 과거 항구도시 빌지워터를 힘으로 장악했으나 지금은 영향력을 잃었다. 하지만 사람들은 그렇기 때문에 오히려 갱플랭크가 더 미쳐 날뛰리라고 생각한다. 갱플랭크는 빌지워터를 다른 사람에게 넘기느니 다시 한 번 피바다로 만들어 버릴 인물이니까. 그리고 이제, 권총, 해적검, 화약통으로 무장한 갱플랭크가 잃었던 패권을 되찾기 위한 준비를 끝냈다.","tags":["전사","고난이도"]},{"name":"Gwen","koreanName":"그웬","imageId":"Gwen","positions":["탑"],"riotClass":"전사","riotSubClass":null,"difficulty":"쉬움","style":["전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"마법의 힘으로 살아나 인간이 된 인형 그웬은 한때 자신을 만들었던 도구를 휘두른다. 발걸음을 내디딜 때마다 자신을 만든 창조자의 사랑을 느끼며 모든 것을 감사히 여긴다. 그웬이 부리는 신성한 안개는 그웬의 가위와 바늘, 실에 축복을 내린 고대의 보호 마법이다. 모든 게 새로운 것으로 가득하지만, 그웬은 망가진 세상에서 살아남은 선한 이들을 위해 기꺼이 싸우러 나선다.","tags":["전사","입문추천"]},{"name":"Gnar","koreanName":"나르","imageId":"Gnar","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"어려움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"고대 요들인 나르는 익살스러운 장난을 치다가도 어린아이 같은 변덕을 부려 벌컥 화를 내며, 그럴 때면 순식간에 거대한 몸집의 야수로 변하여 주변을 마구 때려부순다. 수천 년 동안이나 얼음 정수에 갇혀 있다가 풀려난 터라, 지금의 세계는 나르에게 진기하고 경이로운 세상이다. 호기심 많은 나르는 위험이 닥치면 오히려 즐거워하며, 뼈이빨 부메랑이든 옆에 서 있는 건물이든 닥치는 대로 집어들어 적에게 던진다.","tags":["전사","탱커","고난이도"]},{"name":"Nasus","koreanName":"나서스","imageId":"Nasus","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"보통","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"자칼의 머리를 한 위풍당당한 반인반수 형상의 초월체 나서스는 고대 슈리마의 영웅적인 인물이었다. 날카로운 지력을 소유한 그는 지식의 수호자이자 최고의 전략가로서 수세기 동안 슈리마 제국을 번영으로 인도했다. 제국의 몰락 이후엔 칩거에 들어가 전설 속의 존재가 되었다. 하지만 슈리마의 고대 도시가 되살아나면서, 제국의 몰락이 다시는 일어나지 않도록 하겠다는 다짐과 함께 세상 밖으로 나왔다.","tags":["전사","탱커"]},{"name":"Darius","koreanName":"다리우스","imageId":"Darius","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"녹서스 그 자체를 상징하는 인물로 다리우스만큼 어울리는 사람도 없을 것이다. 실전에서 단련된 사령관이자 녹서스 내에서조차도 두려움의 대상이니까. 다리우스는 미천한 집안에서 태어났으나 녹서스 제국의 적들을 파죽지세로 베어넘기면서 트리파르 군단 사령관이라는 지금의 자리와 권력을 획득했다. 문제는 그 적들 다수가 녹서스 인이었다는 사실이다. 다리우스는 자신의 명분이 정당하다는 것을 한 번도 의심한 적이 없으며, 도끼를 치켜들 때에도 망설임이 없다. 그러니...","tags":["전사","탱커","입문추천"]},{"name":"Rumble","koreanName":"럼블","imageId":"Rumble","positions":["탑"],"riotClass":"전사","riotSubClass":"마법사","difficulty":"매우 어려움","style":["전사","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"럼블은 한 성깔 하는 젊은 요들로, 탁월한 발명가이기도 하다. 두 손과 고철 더미만으로 전기 작살과 소이 로켓을 장착한 거대 기계 로봇을 뚝딱 만들어냈다. 고철부품으로 만든 럼블의 작품을 비웃고 조롱하는 자가 있더라도 럼블은 눈 하나 깜박하지 않는다. 어차피 전장을 휩쓸 화염방사기는 자신의 손에 있으니까.","tags":["전사","마법사","고난이도"]},{"name":"Renekton","koreanName":"레넥톤","imageId":"Renekton","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"불길에 그을린 슈리마 사막에서 다시 일어선 무시무시한 분노의 초월체, 레넥톤. 한 때 그는 슈리마 최고의 전사로서 무수한 전쟁을 승리로 이끌었다. 하지만 슈리마의 몰락과 함께 사막 아래 무덤 속에 갇혔고, 강산이 변하는 억겁의 세월을 어둠 속에서 보내면서 서서히 광기에 굴복해 갔다. 다시 자유의 몸이 된 레넥톤이 원하는 것은 단 하나, 자신을 가둔 형에 대한 복수뿐이다.","tags":["전사","탱커","입문추천"]},{"name":"Riven","koreanName":"리븐","imageId":"Riven","positions":["탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"어려움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"한때 녹서스 군의 소드마스터였던 리븐은 그녀가 정복하려던 땅에서 추방자로 살아가고 있다. 그녀는 확고한 믿음과 잔혹함에 가까운 능력에 힘입어 상급 군인으로 진급하고 전설의 룬 검과 군대를 포상으로 받았다. 그러나 녹서스에 대한 리븐의 믿음은 아이오니아 전선에서 시험대에 올랐고 결국 산산히 깨지고 말았다. 제국과의 모든 연결고리를 끊어버린 그녀는 산산이 조각난 세상 속 몸을 맡길 곳을 찾아 방랑하고 있다. 녹서스 제국이 재건되었다는 무성한 소문에도...","tags":["전사","암살자","고난이도"]},{"name":"Malphite","koreanName":"말파이트","imageId":"Malphite","positions":["탑"],"riotClass":"탱커","riotSubClass":"마법사","difficulty":"매우 쉬움","style":["탱커","마법사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"암석으로 이루어진 거대한 자연물 말파이트는 혼란스러운 세상에 평화로운 질서를 가져오기 위해 노력하고 있다. 말파이트는 원래 다른 세계에서 \'거석\'이라 불리는 돌기둥의 일부이자 거석을 지키는 파수꾼으로 태어났으며, 막강한 자연의 힘으로 거석을 보호하려 했으나 실패하고 말았다. 거석이 파괴된 후, 유일하게 살아남은 말파이트는 이제 룬테라의 물렁물렁한 생명체와 그들의 변덕스러운 성미를 참아내며 마지막 생존자에게 어울리는 새로운 임무를 찾고 있다.","tags":["탱커","마법사","입문추천"]},{"name":"Mordekaiser","koreanName":"모데카이저","imageId":"Mordekaiser","positions":["탑"],"riotClass":"전사","riotSubClass":"마법사","difficulty":"쉬움","style":["전사","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"이미 두 번이나 죽었지만 세 번째로 되살아난 모데카이저는 옛 시대의 잔혹한 군주로서 강령술을 사용해 영혼들을 영원한 노예로 만듭니다. 지금은 그의 정복 활동을 기억하거나, 그의 진정한 힘을 아는 이는 거의 없습니다. 하지만 모데카이저에 대해 잘 아는 일부 고대인들은 그가 다시 돌아와 산 자와 죽은 자 모두를 지배할 날이 도래할까 봐 두려워합니다.","tags":["전사","마법사","입문추천"]},{"name":"Dr. Mundo","koreanName":"문도 박사","imageId":"DrMundo","positions":["탑","정글"],"riotClass":"탱커","riotSubClass":"전사","difficulty":"쉬움","style":["탱커","전사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"완전히 미쳐버린 비참한 살인마이자 오싹한 보라색 괴물로 변한 문도 박사는 많은 자운 시민이 특히나 어두운 밤에 외출을 피하는 이유이다. 현재 의사를 자처하는 그는 한때 자운에서 가장 악명 높은 정신 병원에 수용된 환자였다. 모든 의료진을 \'치료\'하고 나서, 문도 박사는 자신이 치료받았던 빈 병원에서 의사가 된 뒤 본인이 수없이 당한 몹시 부도덕한 치료법을 따라 하기 시작했다. 의약품은 많지만 의학 지식은 전혀 없는 문도 박사는 약물을 주사할 때마다...","tags":["탱커","전사","입문추천","멀티포지션","정글러"]},{"name":"Poppy","koreanName":"뽀삐","imageId":"Poppy","positions":["탑"],"riotClass":"탱커","riotSubClass":"전사","difficulty":"보통","style":["탱커","전사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"룬테라에는 용맹한 챔피언이 넘쳐나지만 뽀삐만큼 끈기 넘치는 이는 찾아보기 힘들다. 제 키의 두 배는 되는 망치 오를론을 들고 다니는 뽀삐는 오랫동안 망치의 정당한 주인이자 전설의 주인공인 데마시아의 영웅을 찾아 비밀스럽게 헤매고 있다. 그 때까지 뽀삐는 충실히 전투로 돌격해 망치를 크게 휘둘러 왕국의 적을 모두 날려 버린다.","tags":["탱커","전사"]},{"name":"Sion","koreanName":"사이온","imageId":"Sion","positions":["탑"],"riotClass":"탱커","riotSubClass":"전사","difficulty":"쉬움","style":["탱커","전사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"과거 사이온은 데마시아 왕을 맨손으로 목 졸라 살해한 전공으로 녹서스에서 존경을 받았다. 이후에는 지나간 시대의 전쟁 영웅으로 잊혀질 뻔했으나, 죽은 후에 부활하여 다시금 녹서스에 충성을 다하게 되었다. 부활한 사이온은 썩어버린 육체에 조악한 방어구를 고정시켜 걸치고, 자신의 앞을 가로막는 자라면 충성 여부에 상관없이 닥치는 대로 학살했다. 죽기 전의 인간성이 더 이상 남아 있지 않은 것이었다. 하지만 그렇게 앞뒤 재지 않고 무작정 전장으로...","tags":["탱커","전사","입문추천"]},{"name":"Sett","koreanName":"세트","imageId":"Sett","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"점점 세력을 더해 가는 아이오니아 범죄 세계의 우두머리 세트는 녹서스와의 전쟁이 끝남과 동시에 두각을 드러내기 시작했다. 나보리 투기장의 신인 투사로 등장한 그는 무지막지한 힘과 상상을 초월하는 맷집으로 금세 유명인사가 되었고, 동네 싸움꾼에서 한때 그가 싸웠던 투기장을 지배하는 정상의 자리까지 올라섰다.","tags":["전사","탱커","입문추천"]},{"name":"Shen","koreanName":"쉔","imageId":"Shen","positions":["탑"],"riotClass":"탱커","riotSubClass":null,"difficulty":"쉬움","style":["탱커"],"gameStyle":"defensive","visual":[],"setting":[],"description":"쉔은 \'킨코우\'라고 하는 아이오니아 비밀결사단의 수장이자, \'황혼의 눈\'이다. 감정, 편견, 아집에서 벗어나는 자유로운 정신을 유지하려 노력하며, 영적 세계와 현실 세계 사이에서 감정에 흔들리지 않는 공명정대함을 실현하기 위해 그 누구도 걷지 않았던 길을 걷는다. 두 세계 사이의 균형을 맞추는 임무를 맡았기에, 그 균형을 위협하려는 자에게 강철검을 휘두르고 신비한 기운을 사용한다.","tags":["탱커","입문추천"]},{"name":"Singed","koreanName":"신지드","imageId":"Singed","positions":["탑"],"riotClass":"탱커","riotSubClass":"마법사","difficulty":"쉬움","style":["탱커","마법사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"뛰어나지만 도의를 모르는 화학자 신지드의 실험은 가장 극악무도한 범죄자조차 역겨워할 정도다. 최고 입찰자에게 자신의 기술을 팔아넘기는 그는 자신이 만든 유독한 혼합물이 어떻게 쓰이든 거의 신경 쓰지 않으며 그로 인한 혼돈마저 하나의 실험으로 여긴다. 신지드의 가장 악명 높은 작품 \'시머\' 덕분에 화공 남작들이 자운을 제멋대로 주무를 수 있게 됐지만, 광기에 사로잡힌 신지드는 늘 새로운 것을 연구하며 그때마다 이전보다 더 끔찍한 실험을 진행한다...","tags":["탱커","마법사","입문추천"]},{"name":"Aatrox","koreanName":"아트록스","imageId":"Aatrox","positions":["탑"],"riotClass":"전사","riotSubClass":null,"difficulty":"쉬움","style":["전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"한때는 공허에 맞서 싸웠던 슈리마의 명예로운 수호자 아트록스와 그의 종족은 결국 공허보다 위험한 존재가 되어 룬테라의 존속을 위협했지만, 교활한 필멸자의 마법에 속아넘어가 패배하게 되었다. 수백 년에 걸친 봉인 끝에, 아트록스는 자신의 정기가 깃든 마법 무기를 휘두르는 어리석은 자들을 타락시키고 육신을 바꾸는 것으로 다시 한번 자유의 길을 찾아내었다. 이제 이전의 잔혹한 모습을 닮은 육체를 차지한 아트록스는 세상의 종말과 오랫동안 기다려온 복수를...","tags":["전사","입문추천"]},{"name":"Ambessa","koreanName":"암베사","imageId":"Ambessa","positions":["탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"매우 어려움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"메다르다라는 이름을 들어본 이는 모두 그 가문의 수장 암베사를 경외합니다. 녹서스 장군으로서의 암베사는 압도적인 힘과 단호한 결단력으로 전투에 나서는 치명적인 존재입니다. 가주로서의 암베사 역시 별반 다르지 않습니다. 메다르다 가문의 권력을 뒷받침하는 건 실패나 동정의 여지를 두지 않는 교활한 책략이기 때문입니다. 늑대의 무자비함을 받아들인 암베사는 가문의 유산을 지키기 위해서라면 무엇이든 할 각오가 되어 있습니다. 그게 자식과의 단절을 뜻하더라도...","tags":["전사","암살자","고난이도"]},{"name":"Ornn","koreanName":"오른","imageId":"Ornn","positions":["탑"],"riotClass":"탱커","riotSubClass":null,"difficulty":"쉬움","style":["탱커"],"gameStyle":"defensive","visual":[],"setting":[],"description":"오른은 대장장이의 일과 그 솜씨를 관장하는 프렐요드의 반신으로, 화산 아래에 있는 용암 동굴 속에 거대한 불꽃 대장간을 짓고 홀로 작업에 몰두한다. 오른이 광석을 녹이고 제련하여 제작하는 물건들은 비할 데 없이 우수한 품질을 자랑한다. 혼자서 밤낮없이 일하는 것을 좋아하지만 다른 신들, 특히 볼리베어가 대지를 걸어다니며 필멸자들을 좌지우지하려 들 때면 대장간에서 나온다. 그러고는 믿음직스러운 망치를 휘두르거나 아예 화산의 힘을 불러내어 그들이...","tags":["탱커","입문추천"]},{"name":"Yorick","koreanName":"요릭","imageId":"Yorick","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"보통","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"오래전 잊힌 종교 교단의 마지막 생존자 요릭은 망자를 거느리는, 축복이자 저주인 능력을 소유하고 있다. 그에게로 몰려드는 썩은 시체와 울부짖는 망령은 그림자 군도에 발이 묶인 그의 유일한 동반자다. 대몰락의 저주로부터 조국을 구원하겠다는 신성한 뜻을 품고 있지만 그의 행동은 괴이하기만 하다.","tags":["전사","탱커"]},{"name":"Urgot","koreanName":"우르곳","imageId":"Urgot","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"어려움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"우르곳은 녹서스 제국에서 맹위를 떨치던 처형인이었으나, 자신이 그토록 숱한 목숨을 거두며 충성했던 조국에게 배신을 당했다. 그는 강철 사슬에 묶여 자운의 깊은 지하에 자리한 광산 감옥인 드레지에서 힘이 갖는 진정한 의미를 배워야 했다. 자운 전체를 혼돈에 빠뜨린 재난을 틈타 드레지를 지배하게 된 우르곳은 이제 범죄가 판을 치는 지하 세계에 짙은 그늘을 드리우고 있다. 한때 자신을 구속했던 바로 그 사슬로 희생자를 옭아매고, 새로운 정착지에서 가치...","tags":["전사","탱커","고난이도"]},{"name":"Irelia","koreanName":"이렐리아","imageId":"Irelia","positions":["탑","미드"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"녹서스에게 침략당한 후 아이오니아에서는 수많은 영웅이 등장했지만, 나보리 출신의 젊은 이렐리아만큼 독특한 영웅은 없다. 이렐리아는 고향 나보리에 전해 내려오는 고대의 춤을 익혔고, 아이오니아가 침략당하자 그 능력을 전쟁터에서의 기술로 삼았다. 치명적인 위력의 칼날들을 공중에 띄우고 자유자재로 조종하며 싸우는 그녀의 모습은 우아하고 신중하며 군더더기라고는 없었다. 훌륭한 투사임을 입증한 이렐리아는 원하는 바는 아니었으나 아이오니아 저항 세력을 선두에서...","tags":["전사","암살자","입문추천","멀티포지션"]},{"name":"Illaoi","koreanName":"일라오이","imageId":"Illaoi","positions":["탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"대 크라켄 신의 여사제, 나가카보로스 신을 섬기는 \'진리의 사도\' 일라오이는 건장한 체격만큼이나 굳건한 신앙심을 지녔다. 거대한 황금빛 성상을 솜인형처럼 가볍게 다루며 상대의 몸과 영혼을 분리하는 모습은 보는 이를 압도하고 적들의 얼을 빼놓기에 충분하다. 그래도 전장에서 일라오이에게 덤벼보겠다면, 바다뱀 군도의 신이 그녀와 함께 한다는 사실을 명심해야 한다.","tags":["전사","탱커","입문추천"]},{"name":"Jax","koreanName":"잭스","imageId":"Jax","positions":["탑","정글"],"riotClass":"전사","riotSubClass":null,"difficulty":"쉬움","style":["전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"독특한 무기와 날카로운 독설 모두 따라올 자가 없는 잭스는 이케시아에서 마지막으로 알려진 무기의 달인이다. 풀려난 공허의 잔해로 조국이 기울자, 잭스와 그 무리는 조국의 남은 부분이나마 수호하기로 맹세했다. 마법이 강해지고 잠재하는 위협이 다시금 태동하자, 잭스는 발로란을 떠돌며 만나는 모든 전사에게 이케시아의 마지막 불빛을 휘두른다. 그와 견줄 수 있을 정도로 강한지 시험하기 위해.","tags":["전사","입문추천","멀티포지션","정글러"]},{"name":"Jayce","koreanName":"제이스","imageId":"Jayce","positions":["탑"],"riotClass":"전사","riotSubClass":"원거리","difficulty":"보통","style":["전사","원거리"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"제이스 탈리스는 친구 빅토르와 함께 마법공학 분야 최초의 위대한 발견을 이뤄 낸 뛰어난 발명가다. 필트오버 전역에서 찬사를 받는 그는 \'진보의 주인공\'이라는 명성에 걸맞게 살고자 하지만 자신을 향한 기대감에 종종 버거워하곤 한다. 이로 인해 제이스는 자신의 발명품이 필트오버와 자운 사이의 분열을 키웠다는 사실을 깨닫기 시작했다. 마법공학 해머로 무장한 그는 내일을 지킬 만반의 준비를 끝냈다.","tags":["전사","원거리"]},{"name":"Cho\'Gath","koreanName":"초가스","imageId":"Chogath","positions":["탑"],"riotClass":"탱커","riotSubClass":"마법사","difficulty":"쉬움","style":["탱커","마법사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"공허에서 나온 생명체 초가스는 룬테라의 따가운 햇빛 아래 처음 모습을 드러낸 순간부터, 그 무엇으로도 만족시킬 수 없는 가장 순수한 굶주림에 이끌려 움직였다. 그 존재 자체가 모든 생명체를 집어삼키려는 공허의 욕망을 온전하게 드러내는 것이다. 초가스는 복잡한 생체 활동을 통해 주변 물질에서 새로운 몸을 만들어냈고, 근육과 밀도를 키웠으며, 유기체 다이아몬드처럼 딱딱한 겉껍질로 몸을 덮었다. 하지만 몸집이 커져도 허기를 채울 수 없자, 초가스는 여분의...","tags":["탱커","마법사","입문추천"]},{"name":"Camille","koreanName":"카밀","imageId":"Camille","positions":["탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"카밀은 법이라는 테두리 밖에서 활동할 수 있도록 아예 자신의 몸을 무기화해 버렸다. 우아한 엘리트 첩보원이자 페로스 가문이 배출한 최고 정보 요원인 그녀의 임무는 고도화된 필트오버와 그 하층부의 자운이 원활하게 돌아가도록 기여하는 것이다. 적응력이 뛰어나고, 정확성을 중시하므로 엉성한 기술은 반드시 정리해 버려야 할 수치로 여긴다. 마법공학 증강을 통해 최고가 되려는 노력, 그리고 자신이 품고 있는 칼만큼이나 예리한 지성을 지닌 카밀의 모습을 보면...","tags":["전사","암살자","입문추천"]},{"name":"Kennen","koreanName":"케넨","imageId":"Kennen","positions":["탑"],"riotClass":"마법사","riotSubClass":null,"difficulty":"쉬움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"케넨은 아이오니아의 균형을 수호하는 번개같이 빠른 집행자이기도 하지만, 킨코우 결사단에서 유일한 요들이기도 하다. 작고 복실복실한 외모와는 달리 케넨은 수리검으로 일으키는 소용돌이 폭풍과 끝없는 열정으로 그 어떤 위협도 극복할 준비가 되어있다. 케넨은 사부인 쉔과 함께 영적인 영역을 순찰하며 엄청난 번개의 힘으로 적을 쓰러뜨린다.","tags":["마법사","입문추천"]},{"name":"Kayle","koreanName":"케일","imageId":"Kayle","positions":["탑"],"riotClass":"마법사","riotSubClass":"원거리","difficulty":"보통","style":["마법사","원거리"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"룬 전쟁이 한창일 때 태어난 케일은 정의의 성위인 어머니의 뜻을 이어받아 신성한 불꽃의 날개를 펴고 정의를 실현하기 위해 싸웠다. 그리고 쌍둥이 동생 모르가나와 함께 데마시아의 수호자로 수년간 추앙받았다. 그러나 인간들의 반복된 실수에 환멸을 느낀 케일은 결국 데마시아를 영원히 떠나고 말았다. 불타는 검을 휘두르며 악을 심판하는 케일의 이야기는 데마시아의 전설이 되었고, 여전히 많은 이들은 케일의 재림을 간절히 바라고 있다.","tags":["마법사","원거리"]},{"name":"Quinn","koreanName":"퀸","imageId":"Quinn","positions":["탑"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"쉬움","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"데마시아의 정예 기동대 기사인 퀸은 전설적인 독수리 발러와 함께 적의 영토 한복판에 잠입해 갖가지 위험한 임무를 수행한다. 퀸과 발러의 강력한 결속력은 전투에서 무시무시한 힘을 발휘한다. 적들은 그들의 상대가 데마시아 제일가는 영웅, 그것도 하나가 아니라 둘이라는 사실을 알지도 못한 채 순식간에 목숨을 잃고 만다. 상황에 따라 곡예 수준의 동작을 보여주는 퀸이 민첩한 몸놀림으로 석궁을 꺼내들면, 발러는 공중에서 유영하며 숨어 있는 적을 찾아낸다...","tags":["원거리","암살자","입문추천"]},{"name":"K\'Sante","koreanName":"크산테","imageId":"KSante","positions":["탑"],"riotClass":"탱커","riotSubClass":"전사","difficulty":"어려움","style":["탱커","전사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"용감하고 도전적인 크산테는 누구나 탐내는 슈리마 사막 속의 오아시스, 고향 나주마를 지키기 위해 거대한 짐승과 무자비한 초월체에 맞서 싸운다. 하지만 크산테는 예전 파트너와 사이가 틀어진 후 나주마를 이끌 만한 전사가 되려면 성공만을 향해 달려가는 아집을 버려야 한다는 것을 깨달았다. 그래야만 긍지라는 덫에 빠지지 않고 나주마 사람들을 위협하는 포악한 괴물들을 물리치는 데 필요한 지혜를 찾을 수 있을 것이다.","tags":["탱커","전사","고난이도"]},{"name":"Kled","koreanName":"클레드","imageId":"Kled","positions":["탑"],"riotClass":"전사","riotSubClass":null,"difficulty":"보통","style":["전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"용감무쌍하고도 성깔 고약한 전사인 클레드는 녹서스 특유의 객기와 다혈질을 상징하는 존재와도 같다. 그래서 병사들 사이에서는 인기를 휩쓸지만, 장성들 사이에서는 불신의 대상이고, 귀족들에게는 혐오를 한몸에 사고 있다. 소문에 따르면 클레드는 녹서스 제국이 처음 세워진 시절부터 지금까지 모든 군사 작전에서 활약해왔으며, 단 한 번도 후퇴한 적이 없고, 군인으로서 받을 수 있는 칭호란 칭호는 모조리 \'따냈다\'고 전해진다. 하지만 병사들의 이야기가 과연...","tags":["전사"]},{"name":"Tryndamere","koreanName":"트린다미어","imageId":"Tryndamere","positions":["탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"한때 트린다미어는 걷잡을 수 없는 분노와 증오의 힘을 원동력 삼아, 프렐요드를 돌아다니며 북방 제일가는 위대한 전사들에게 공공연한 도전을 일삼았다. 앞으로 닥칠 더욱 암울한 미래를 대비하기 위함이었다. 분노의 야만전사로서, 부족을 말살시킨 원수에게 복수할 날만을 고대하고 있었던 것이다. 하지만 최근에는 아바로사의 전쟁의 어머니인 애쉬의 동료가 되어 아바로사 부족민들과 함께 살고 있다. 트린다미어의 초인적인 힘과 전설에 나올 법한 불굴의 투지에 힘입어...","tags":["전사","암살자","입문추천"]},{"name":"Teemo","koreanName":"티모","imageId":"Teemo","positions":["탑"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"어떤 위협에도 꿈쩍 않는 티모는 끝 모를 적극성과 쾌활함으로 세상을 정찰한다. 티모는 확고한 도덕성을 가진 요들로, 밴들 시티의 정찰대 강령을 따르는 것을 자랑스럽게 여긴다. 강령을 얼마나 열심히 따르는지 그의 행동이 가져올 더 넓은 결과를 깨닫지 못하기도 한다. 더러 정찰대의 존재에 의문을 품는 자들도 있지만, 한 가지는 분명하다. 티모의 신념은 절대 얕잡아봐서는 안 된다.","tags":["원거리","마법사"]},{"name":"Fiora","koreanName":"피오라","imageId":"Fiora","positions":["탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"매우 쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"발로란을 통틀어 가장 무시무시한 데마시아 왕국의 결투가, 피오라. 푸른 강철 레이피어를 다루는 솜씨만큼이나 가차없는 태도와 재빠른 머리 회전으로 유명한 그녀는 아버지가 일으킨 스캔들로 집안의 명성이 땅에 떨어진 후 가문의 지배권을 넘겨받았다. 로렌트 가문의 명성은 더럽혀진 지 오래지만, 피오라는 가문의 명예를 되찾고 데마시아의 위대한 가문으로 일궈온 자리를 되찾기 위해 온 힘을 다하고 있다.","tags":["전사","암살자","입문추천"]}],"정글":[{"name":"Gragas","koreanName":"그라가스","imageId":"Gragas","positions":["정글","탑"],"riotClass":"전사","riotSubClass":"마법사","difficulty":"쉬움","style":["전사","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"그라가스는 몸집이 크고 소란스러워서 한 번 보면 잊기 힘든 쾌활한 주조가로, 언제나 모두의 기운을 북돋울 새로운 방법을 찾고 있습니다. 그라가스가 어디서 왔는지는 아무도 모르지만, 프렐요드의 때 묻지 않은 불모지를 뒤지며 희귀한 재료를 찾아 완벽한 최신 혼합물을 만듭니다. 그라가스는 완고하고, 충동적이며, 소동을 일으키는 것으로 유명한데, 그 소동은 밤샘 파티와 엄청난 기물 파손으로 이어지곤 합니다. 그라가스를 보게 된다면 곧 즐거움, 그리고 파괴가...","tags":["전사","마법사","입문추천","멀티포지션","정글러"]},{"name":"Graves","koreanName":"그레이브즈","imageId":"Graves","positions":["정글"],"riotClass":"원거리","riotSubClass":null,"difficulty":"매우 쉬움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"말콤 그레이브즈는 명성이 자자한 용병, 도박사, 도적으로, 그가 한 번이라도 발을 들였던 모든 도시와 제국에서 수배령이 떨어져 있을 정도다. 그레이브즈는 성미가 불 같지만, 범죄의 명예에 엄격한 면이 있어 자신의 이중 총열 산탄총 \'운명\'으로 마무리를 하는 경우가 잦다. 최근에는 트위스티드 페이트와 함께 바람 잘 날 없던 파트너 관계를 다시 맺고, 범죄의 냄새가 나는 빌지워터의 그늘진 곳에서 벌어지는 소동을 다시 한 번 주름잡고 있다.","tags":["원거리","입문추천","정글러"]},{"name":"Nocturne","koreanName":"녹턴","imageId":"Nocturne","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"언제부터인가 자의식이 있는 존재라면 반드시 꾸는 악몽이 있었다. 그리고 그 악몽들이 모여 사악한 기운을 끌어들였고, 그 속에서 태곳적 힘을 지닌 순수한 악 그 자체인 녹턴이 생겨났다. 녹턴은 혼돈을 암흑의 액체로 표현한 듯한 형상으로, 얼굴은 없으나 차디찬 눈을 지녔으며 흉흉해 보이는 칼날로 무장했다. 영혼계에서 탈출하여 생명이 깨어 있는 세계로 내려온 녹턴은 진정한 암흑에서나 피어날 법한 공포를 먹이로 삼는다.","tags":["전사","암살자","입문추천","정글러"]},{"name":"Nunu & Willump","koreanName":"누누와 윌럼프","imageId":"Nunu","positions":["정글"],"riotClass":"탱커","riotSubClass":"마법사","difficulty":"쉬움","style":["탱커","마법사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"아주 오랜 옛날, 무시무시한 괴물을 물리쳐 영웅이 되고 싶은 소년이 있었다. 하지만 소년이 발견한 것은 마법을 부리는, 단지 친구가 필요했던 외로운 설인이었다. 고대의 힘과 눈싸움으로 하나가 된 소년 누누와 설인 윌럼프는 프렐요드 곳곳을 누비며 상상 속의 모험을 떠난다. 실종된 누누의 어머니를 찾아 나선 누누와 윌럼프. 이들이 누누의 어머니를 구한다면 영웅이 될 수 있을지도...","tags":["탱커","마법사","입문추천","정글러"]},{"name":"Nidalee","koreanName":"니달리","imageId":"Nidalee","positions":["정글"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"깊은 정글에서 자라난 니달리는 자신의 형태를 흉포한 쿠거로 자유자재로 변화시킬 수 있는 추적의 달인이다. 완전한 여인도, 완전한 야수도 아닌 니달리는 신중하게 배치한 덫과 재빠른 창 투척으로 모든 침입자들로부터 자신의 영역을 맹렬하게 지켜낸다. 니달리는 사냥감을 움직이지 못하게 공격한 후 쿠거 형태로 변해 덮친다. 니달리에게서 운 좋게 살아남은 몇 사람은 야생에 사는 여자가 있다는 이야기를 퍼뜨렸다. 본능이 극도로 예리하고, 발톱은 그보다도 더...","tags":["암살자","마법사","고난이도","정글러"]},{"name":"Diana","koreanName":"다이애나","imageId":"Diana","positions":["정글","미드"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"다이애나는 오늘날 거의 사멸된 고대 종교 \'루나리\'의 전사이자, 은빛 달의 화신 그 자체다. 그녀는 드높은 타곤 산 꼭대기에 떠오른 천체들의 기운을 온몸으로 받아들였고, 겨울 밤 설원처럼 은은하게 빛나는 갑옷과 초승달 검으로 무장했다. 그러나 인간을 초월한 그녀의 힘이 무엇을 위한 것인지는 아직까지 분명하지 않다. 다이애나는 이 세상에서 자신에게 부여된 사명이 무엇인지 알아내려 애쓰고 있다.","tags":["전사","암살자","입문추천","멀티포지션","정글러"]},{"name":"Rammus","koreanName":"람머스","imageId":"Rammus","positions":["정글"],"riotClass":"탱커","riotSubClass":null,"difficulty":"쉬움","style":["탱커"],"gameStyle":"defensive","visual":[],"setting":[],"description":"알 수 없는 신비의 존재 람머스. 누군가에게는 숭배의 대상이고, 또 누군가에게는 경외의 대상인 우상과도 같은 인물. 더러는 우리와 똑같은 인간으로 여겨지는 경우도 있다. 하지만 한 가지 분명한 것은 그 누구도 람머스의 정체를 제대로 알지 못한다는 것. 베일에 가려진 수수께끼의 존재라는 사실이다. 뾰족한 못이 박힌 갑옷을 입고 다니는 그를 두고 사람들은 여러가지 추측을 내놓는다. 반신반인의 존재라느니, 신성한 사제라느니, 마술에 걸린 야수일 뿐이라는...","tags":["탱커","입문추천","정글러"]},{"name":"Rek\'Sai","koreanName":"렉사이","imageId":"RekSai","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"최상위 포식자 렉사이는 무자비한 공허 태생 생명체로, 땅굴을 파고 들어가 있다가 방심한 먹잇감을 덮쳐 게걸스럽게 집어삼킨다. 렉사이의 그칠 줄 모르는 식탐 때문에 위대한 슈리마 제국 전체가 초토화되었을 정도다. 사막을 오가는 상인이나 여행자들은 아무리 철저하게 무장을 했더라도 렉사이의 영토를 피하려고 일부러 멀고 먼 길을 돌아가곤 한다. 렉사이가 지평선에 보이면, 지하에서 기다리고 있는 것은 죽음 뿐이라는 것을 모르는 사람은 없다.","tags":["전사","탱커","입문추천","정글러"]},{"name":"Rengar","koreanName":"렝가","imageId":"Rengar","positions":["정글","탑"],"riotClass":"암살자","riotSubClass":"전사","difficulty":"어려움","style":["암살자","전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"포악한 기질의 렝가는 바스타야 종족으로, 난폭하고 사나운 생명체를 추적하고 처치하는 순간의 짜릿한 전율을 삶의 낙으로 여기는 전리품 수집가다. 그는 강하고 무시무시한 괴물을 사냥하기 위해 온 세상을 샅샅이 뒤진다. 그중에서도 그가 가장 찾고자 하는 사냥감은 그의 한쪽 눈을 앗아간 공허의 약탈자 카직스다. 렝가가 사냥을 하는 이유는 굶주린 배를 채우기 위함도, 영광을 누리기 위함도 아니다. 그는 사냥 그 자체의 즐거움을 만끽하기 위해 오늘도 먹잇감을...","tags":["암살자","전사","고난이도","멀티포지션","정글러"]},{"name":"Lee Sin","koreanName":"리 신","imageId":"LeeSin","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"보통","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"리 신은 아이오니아에 전해 내려오는 고대 무술에 통달했다. 지조 높고 고결한 전사로, 싸워야 할 때에는 용의 혼의 정수를 끌어낸다. 오래 전에 시각을 잃었으나, 고향 땅의 신성한 균형을 해치려 드는 자를 막아내는 데 일생을 바치겠다는 신념은 흔들림이 없다. 명상에 잠긴 듯 고요한 태도를 얕보고 함부로 덤벼드는 적은 리 신의 불꽃 같은 주먹과 초인적 위력의 돌려차기에 속수무책으로 당한다.","tags":["전사","암살자","정글러"]},{"name":"Lillia","koreanName":"릴리아","imageId":"Lillia","positions":["정글"],"riotClass":"전사","riotSubClass":"마법사","difficulty":"어려움","style":["전사","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"부끄럼을 많이 타는 사슴, 릴리아는 조심스럽게 아이오니아의 숲을 배회한다. 필멸자들의 모습에 매료되면서도, 동시에 공포를 느끼는 그녀는 꿈꾸는 나무에 인간들의 꿈이 흘러들지 않는 이유를 궁금해한다. 이제 릴리아는 마법이 깃든 나뭇가지를 손에 쥐고 아이오니아를 여행한다. 이뤄지지 못한 인간들의 꿈을 찾고, 그들의 빛을 가리고 있는 공포를 없애야만 릴리아 역시 활짝 피어날 수 있기 때문이다.","tags":["전사","마법사","고난이도","정글러"]},{"name":"Master Yi","koreanName":"마스터 이","imageId":"MasterYi","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"마스터 이는 수련을 통해 심신을 갈고 닦아, 마침내 생각과 행동이 일치하는 경지에 이르렀다. 최후의 수단으로 무력을 사용할 것을 결심하기는 했지만, 마스터 이는 품위 있고 빠른 검 놀림으로 자신의 결단을 언제나 빠르게 수행했다. 아이오니아의 우주류 검술의 살아있는 마지막 전승자인 마스터 이는 자신의 \'통찰의 칠안경\'과 함께 제자가 되려는 후보자 중 가장 적합한 자를 꼼꼼히 조사하는 등 고향의 유산을 이어가는 데에 일생을 바친다.","tags":["전사","암살자","입문추천","정글러"]},{"name":"Vi","koreanName":"바이","imageId":"Vi","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"자운의 암흑가에서 자란 다혈질 성격의 바이는 충동적이고 성급한 데다가 권위에 대한 존중이라고는 눈곱만큼도 없다. 윗동네에서 사고를 치고 다니던 어린 시절에도 스틸워터 교도소에서 부당하게 긴 징역살이를 했을 때도 언제나 상황을 빠르게 판단하며 살아남았다. 이제 평화를 깨는 대신 유지하기 위해 필트오버의 집행자가 된 바이는 육중한 벽을 단숨에 부술 만큼 무시무시한 마법공학 건틀릿을 휘두르며 범죄자를 색출하고 있다.","tags":["전사","암살자","입문추천","정글러"]},{"name":"Belveth","koreanName":"벨베스","imageId":"Belveth","positions":["정글"],"riotClass":"전사","riotSubClass":null,"difficulty":"매우 어려움","style":["전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"잡아먹힌 도시를 재료로 만들어진 사악한 여제 벨베스는 룬테라의 종말이자, 자신이 만든 끔찍한 현실의 시작이기도 하다. 그녀는 지상 세계의 바뀐 역사와 지식, 기억의 시대에 힘입어 새로운 경험과 감정에 대한 갈망을 채우고, 마주치는 모든 것을 집어삼킨다. 하지만 하나의 세계만으로 굶주림을 채우지 못한 벨베스는 공허의 옛 주인들에게 눈을 돌린다...","tags":["전사","고난이도","정글러"]},{"name":"Volibear","koreanName":"볼리베어","imageId":"Volibear","positions":["정글","탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"추종자들에게 볼리베어는 여전히 폭풍 그 자체이다. 강력하고 야만적이며 고집스러울 정도로 단호한 그는 프렐요드의 동토에 필멸자들이 나타나기 전부터 존재했다. 다른 반신들과 함께 일구어낸 그 땅을 무척이나 아끼는 볼리베어는 나약하기 그지없는 문명의 발달을 극도로 혐오했고, 결국 거칠고 폭력적이었던 옛 전통을 되찾기 위해 싸움을 시작한다. 그 앞을 가로막는 자는 누구든 볼리베어의 이빨과 발톱, 천둥의 위력을 맛보게 될 것이다.","tags":["전사","탱커","입문추천","멀티포지션","정글러"]},{"name":"Briar","koreanName":"브라이어","imageId":"Briar","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"매우 쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"검은 장미단의 실패한 실험으로 탄생한 브라이어는 피를 향한 갈망을 통제할 수 없어서 특수 족쇄로 광기를 다스려야 했다. 몇 년이나 갇혀있던 끝에, 살아있는 무기인 브라이어는 구속에서 벗어나 바깥세상에 풀려났다. 브라이어는 이제 누구의 통제도 받지 않는다. 지식과 피에 목마른 브라이어는 마음껏 날뛸 기회를 마다하지 않는다. 물론 그 뒤에 광증을 억누르는 것이 쉽진 않지만.","tags":["전사","암살자","입문추천","정글러"]},{"name":"Viego","koreanName":"비에고","imageId":"Viego","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"비에고는 오래전 잊힌 왕국의 지배자였다. 천년도 전에, 그는 아내 이졸데를 죽음에서 되찾고자 시도한 끝에 현재 대몰락으로 불리는 마법 재해를 일으켰다. 그 안에서 죽음을 맞은 비에고는 강력한 언데드 망령이 되었으나, 죽은 지 수백 년은 지난 왕비를 향한 집착에 여전히 고통받았다. 이제 비에고는 몰락한 왕으로 군림하여 죽음의 해로윙을 지배한다. 이졸데를 치유할 가망이 있는 것이라면 무엇이든 찾아 룬테라를 뒤지며, 잔혹한 심장의 상처에서 끝없이 쏟아지는...","tags":["전사","암살자","입문추천","정글러"]},{"name":"Shaco","koreanName":"샤코","imageId":"Shaco","positions":["정글"],"riotClass":"암살자","riotSubClass":null,"difficulty":"어려움","style":["암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"샤코는 오래 전, 외로움을 타던 어느 왕자를 위한 장난감으로 만들어졌다. 하지만 이제는 살육과 참사를 즐기는 마법 깃든 인형이다. 이전에는 친절한 마음씨를 지닌 광대였지만, 흑마법으로 타락하고 사랑하는 이를 잃은 상실감 때문에 오로지 불쌍한 인간들을 고문하는 것에서만 기쁨을 느끼게 되었다. 장난감과 단순한 속임수를 이용하여 상대를 농락하고 목숨을 빼앗은 다음, 유혈낭자한 \'유희\'의 결과에 만족하며 웃는다. 한밤중에 음산한 웃음소리가 들리는가?...","tags":["암살자","고난이도","정글러"]},{"name":"Sejuani","koreanName":"세주아니","imageId":"Sejuani","positions":["정글"],"riotClass":"탱커","riotSubClass":null,"difficulty":"쉬움","style":["탱커"],"gameStyle":"defensive","visual":[],"setting":[],"description":"세주아니는 프렐요드에서 가장 공포스러운 부족 중 하나로 꼽히는 겨울 발톱 부족의 잔혹하고 무자비한 냉기의 화신이자 전쟁의 어머니이다. 세주아니의 부족은 생존을 위해 자연과 끊임 없이 절박한 싸움을 했고, 혹독한 겨울에서 살아남기 위해 녹서스, 데마시아, 아바로사를 침공해야 했다. 세주아니는 가장 위험한 공격의 선봉에 서서 멧돼지 브리슬의 안장에 타고 얼음 정수의 철퇴를 휘둘러 적을 얼리고 깨뜨린다.","tags":["탱커","입문추천","정글러"]},{"name":"Shyvana","koreanName":"쉬바나","imageId":"Shyvana","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"쉬바나는 무시무시한 하프 드래곤 전사로서, 평소에는 인간의 모습을 하고 있으나, 용의 형상으로 변하면 하늘을 지배하며 불타오르는 숨결로 적을 그 자리에서 태워버린다. 자르반 4세의 목숨을 구해준 후 그의 친위대에 들어갔지만, 데마시아인들은 여전히 쉬바나에게 미심쩍은 눈길을 보내고 있다. 쉬바나로서도 친위대원 노릇이나 데마시아인들의 신임을 받는 일이 쉽지만은 않다.","tags":["전사","탱커","입문추천","정글러"]},{"name":"Skarner","koreanName":"스카너","imageId":"Skarner","positions":["정글"],"riotClass":"탱커","riotSubClass":"전사","difficulty":"쉬움","style":["탱커","전사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"거대한 고대 브래컨, 스카너는 지배 계급인 윤 탈의 창립 일원으로 이쉬탈에서 추앙받는다. 자신의 나라를 외부 세계로부터 안전하게 지키기 위해 헌신하는 스카너는 이샤오칸 아래 내실에서 살아가며 대지의 진동에 귀를 기울이고 잠재적 위협을 감지한다. 이쉬탈의 고립에 의문을 품는 윤 탈의 구성원이 많아지면서 스카너의 편집증은 갈수록 심해지고 있다. 이쉬탈과 이쉬탈 사람들의 안전을 지키기 위해서라면 스카너는 무엇이든 할 것이다. 어떤 대가가 따르더라도.","tags":["탱커","전사","입문추천","정글러"]},{"name":"Xin Zhao","koreanName":"신 짜오","imageId":"XinZhao","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"신 짜오는 데마시아를 통치하는 라이트실드 왕조에 충성을 바치는 결의에 가득 찬 전사이다. 신 짜오는 한 때 녹서스의 검투사로 싸우는 형벌에 처해져 셀 수 없이 많은 시합에서 살아남았지만 데마시아 군이 신 짜오를 해방시켜 준 후, 용감한 해방군인 데마시아 군에 목숨을 다해 충성하기로 맹세했다. 손에 익은 삼조창으로 무장한 신 짜오는 이제 자신을 받아들여 준 데마시아 왕국을 위해 어떤 적이 어떠한 상황에서 달려든다 해도 담대하게 맞선다.","tags":["전사","탱커","입문추천","정글러"]},{"name":"Amumu","koreanName":"아무무","imageId":"Amumu","positions":["정글","서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"매우 쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"뼛속까지 사무치는 외로움과 쓸쓸함 속에 살아가는 아무무. 평생을 오로지 마음을 나눌 수 있는 단 한 명의 친구를 찾아 헤매는, 고대 슈리마 제국의 가엾은 영혼이다. 끔찍한 저주를 받은 아무무는 영원히 혼자인 채로 남겨졌다. 그 저주란 지독하리만큼 잔인한 것이었다. 상대가 누구든 아무무와의 신체적 접촉은 죽음을 의미했고 정서적 교류는 파멸을 불러왔다. 그의 운명을 아는 한 누구도 그를 가까이하려 들지 않았다. 간혹 아무무를 봤다는 이들은 그를 두고...","tags":["탱커","서포터","입문추천","멀티포지션","정글러"]},{"name":"Ivern","koreanName":"아이번","imageId":"Ivern","positions":["정글"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"보통","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"자연의 아버지로 잘 알려진 아이번 브램블풋은 룬테라 전역의 숲을 돌아다니며 생명을 가꾼다. 반은 인간, 반은 나무의 형상을 한 그는 자연의 비밀을 속속들이 알고 있을 뿐 아니라 땅에서 자라고, 하늘을 날고, 초원을 달리는 모든 것과 깊은 친분을 맺고 있다. 아이번은 자연 속에서 만나는 모든 이에게 자신만의 지혜를 나누어 주고, 숲을 풍성하게 가꾸며, 때로는 입이 가벼운 나비들에게 비밀을 맡기기도 한다.","tags":["서포터","마법사","정글러"]},{"name":"Ekko","koreanName":"에코","imageId":"Ekko","positions":["정글","미드"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"자운 뒷골목 출신의 천재 소년 에코는 언제든 자신에게 유리하게 시간을 조작할 수 있다. 직접 발명한 Z 드라이브를 이용해 다양한 시공간에서 가능성의 갈래를 탐험하며 완벽한 순간을 포착하는 에코는 한 번의 시행착오도 없이 매번 불가능한 일을 해내는 것처럼 보인다. 누구보다도 자유로운 영혼을 가졌지만 소중한 사람들을 구하기 위해서라면 점화단과 함께 어떤 위험도 무릅쓴다.","tags":["암살자","마법사","고난이도","멀티포지션","정글러"]},{"name":"Elise","koreanName":"엘리스","imageId":"Elise","positions":["정글"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"엘리스는 녹서스 불멸의 요새 깊숙한 곳에 있는 저택에서 빛을 차단하고 은둔해 사는 치명적인 포식자다. 필멸자 시절 그녀는 명문가의 안주인이였지만 끔찍한 반신에 물린 후 매혹적이면서도 무자비한 거미와 같은 존재가 되어 먹잇감을 거미줄로 끌어들였다. 영원한 젊음을 유지하기 위해 엘리스는 거부하기 힘든 유혹을 펼치며 무고한 이들을 사냥한다.","tags":["암살자","마법사","고난이도","정글러"]},{"name":"Wukong","koreanName":"오공","imageId":"MonkeyKing","positions":["정글","탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"오공은 바스타야로, 자신의 뛰어난 힘, 민첩성과 지혜로 상대방을 혼란에 빠뜨려 유리한 고지를 차지하는 악동이다. 마스터 이로 알려진 평생지기를 찾은 뒤, 오공은 우주류로 알려진 고대 무술의 마지막 제자가 되었다. 마법봉으로 무장한 오공은 아이오니아의 파멸을 막고자 한다.","tags":["전사","탱커","입문추천","멀티포지션","정글러"]},{"name":"Olaf","koreanName":"올라프","imageId":"Olaf","positions":["정글","탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"그 누구도 막지 못할 파괴력으로 도끼를 휘두르는 올라프가 바라는 것은 딱 한 가지, 전장에서 영광스럽게 전사하는 것이다. 프렐요드에서도 가혹한 환경으로 유명한 록파르 반도 출신인 올라프는 어느 날 자신이 무병장수하다가 평온하게 숨을 거둘 것이라는 예언을 들었다. 록파르에서는 침상에서 편안하게 죽는 것은 겁쟁이뿐이므로, 이는 더할 나위 없이 모욕적인 운명이었다. 분노가 치민 올라프는 오로지 싸우다 죽기만을 바라며 프렐요드를 종횡무진했다. 하지만 위대한...","tags":["전사","탱커","입문추천","멀티포지션","정글러"]},{"name":"Udyr","koreanName":"우디르","imageId":"Udyr","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"보통","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"현존하는 최강의 정령 주술사 우디르는 프렐요드의 모든 정령과 교감하며 정령이 바라는 바를 마음으로 이해하고 정령의 힘을 불러모아 우디르 특유의 고대 전투 방식을 선보인다. 우디르는 자신의 정신이 다른 이들로 인해 어지럽혀지지 않도록 내면의 균형을 추구하지만 외부의 균형도 함께 추구한다. 프렐요드의 신비로운 힘은 갈등과 역경을 이겨낸 성장이 있어야만 강해질 수 있기 때문이다. 우디르는 평화에 젖어 쇠락하지 않으려면 희생이 필요하다는 사실을 알고 있다.","tags":["전사","탱커","정글러"]},{"name":"Warwick","koreanName":"워윅","imageId":"Warwick","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"자운의 잿빛 골목을 무대로 사냥감을 찾는 괴수 워윅. 극한의 고통을 동반하는 각종 실험으로 완전히 변형된 그의 육체는 약품통, 펌프, 여러 기계가 결합된 복잡한 시스템과 연결되어 있으며, 정맥에는 연금술을 통해 조합한 분노가 주입된다. 어두운 그림자 속에서 느닷없이 튀어나오곤 하는 그는 사람들을 위협하는 도시의 범죄자들을 단숨에 사냥한다. 피 냄새를 맡고 나면 이성을 잃고 마는 워윅... 조금이라도 피를 흘린 자는 그 누구도 워윅의 손아귀에서 벗어날...","tags":["전사","탱커","입문추천","정글러"]},{"name":"Evelynn","koreanName":"이블린","imageId":"Evelynn","positions":["정글"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"매우 어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"룬테라의 어두운 경계선 안에서, 악마 이블린은 다음 먹잇감을 찾고 있다. 먼저 관능적인 인간 여성의 얼굴로 사냥감을 유혹한다. 희생자가 그 매력에 넘어오면, 이블린은 악마의 참모습을 드러낸다. 이블린은 희생자에게 말로 형언할 수 없는 고통을 안기고, 자신은 그 고통에 희열을 느낀다. 이블린이라는 악마에게는 이것이 한바탕 즐기는 유희일 뿐이지만, 룬테라 주민에게는 엇나간 욕망을 발산했다가는 그 대가로 끔찍한 종말을 맞게 되리라는 교훈을 되새겨주는...","tags":["암살자","마법사","고난이도","정글러"]},{"name":"Jarvan IV","koreanName":"자르반 4세","imageId":"JarvanIV","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"라이트실드 왕조의 자손인 자르반 왕자는 데마시아의 왕좌를 물려받을 후계자이다. 데마시아의 덕목을 대표하는 귀감으로 자라난 자르반 왕자는 자신의 어깨에 짊어진 큰 기대와 전선에서 싸우고 싶다는 개인적 욕망 사이에서 갈등해야 했다. 자르반 왕자는 가공할 만한 용기와 자신을 돌보지 않는 투지로 병사들을 고무시키며, 데마시아의 기치를 높이 들고 자신의 백성을 이끄는 미래의 지도자로서 진정한 힘을 뿜어낸다.","tags":["전사","탱커","입문추천","정글러"]},{"name":"Zac","koreanName":"자크","imageId":"Zac","positions":["정글"],"riotClass":"탱커","riotSubClass":"전사","difficulty":"어려움","style":["탱커","전사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"자크는 화학공학 지층을 따라 흐른 독성물질이 자운의 지하동굴 깊은 곳에 위치한 웅덩이에 모여 만들어진 생명체이다. 이처럼 변변치 못한 태생에도 불구하고 자크는 원시적인 진흙의 상태에서 지성을 갖춘 존재로 성장했다. 그는 자운의 배관 속에 살면서 도움이 필요한 이들을 돕거나 자운의 망가진 기반시설을 재건하기 위해 이따금 모습을 드러낸다.","tags":["탱커","전사","고난이도","정글러"]},{"name":"Karthus","koreanName":"카서스","imageId":"Karthus","positions":["정글","미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"보통","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"망각을 부르는 자 카서스는 섬뜩한 노랫소리를 전주곡 삼아 악몽처럼 등장하는 언데드이다. 산 자는 영원히 죽지 않는 언데드를 두려워하나, 그는 언데드를 삶과 죽음의 완벽한 결합으로 오직 아름답고 순수하다 여긴다. 카서스는 언데드로서 존재하는 기쁨을 온 세계에 전하기 위해 그림자 군도로부터 출몰한다.","tags":["마법사","멀티포지션","정글러"]},{"name":"Kha\'Zix","koreanName":"카직스","imageId":"Khazix","positions":["정글"],"riotClass":"암살자","riotSubClass":null,"difficulty":"보통","style":["암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"\'공허는 성장하고, 공허는 적응한다.\' 공허태생 생명체는 많지만, 이 진리를 카직스보다 더 명백히 입증하는 존재는 없다. 카직스가 공포스러운 것은 진화를 거듭하기 때문이다. 생존을 위해 사냥을 하고, 사냥감을 집어삼킬 때마다 강해지고, 더 강한 상대를 찾아 또다시 사냥에 나선다. 게다가 진화를 할수록 먹이를 낚아채는 사냥 기술은 더 새로워지고 효율도 높아진다. 공허에서 갓 넘어왔을 때에는 아무 생각 없는 야수에 불과했으나, 이제는 그 형체만큼이나...","tags":["암살자","정글러"]},{"name":"Kayn","koreanName":"케인","imageId":"Kayn","positions":["정글"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"어려움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"치명적인 그림자 마법을 그 누구보다도 자유자재로 구사하는 자, 시이다 케인이 싸우는 이유는 자신에게 주어진 진정한 운명을 실현하기 위해서다. 장차 그림자단을 이끌고 아이오니아가 패권을 장악하는 새로운 시대를 열 것이라는 운명. 케인은 자의식이 있는 다르킨 무기 라아스트를 들고 전장에 나선다. 다르킨 무기는 그것을 휘두르는 자의 몸과 정신을 서서히 타락시킨다는 사실은 아랑곳하지 않는 것이다. 다르킨 무기에 손을 댄 이상 예상할 수 있는 결과는 단 두...","tags":["전사","암살자","고난이도","정글러"]},{"name":"Kindred","koreanName":"킨드레드","imageId":"Kindred","positions":["정글"],"riotClass":"원거리","riotSubClass":null,"difficulty":"쉬움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"킨드레드는 따로지만 언제나 함께인 죽음의 양면을 지닌 존재다. 운명을 받아들인 자에게는 양의 화살로 빠른 죽음을 선사하고, 운명을 거부하고 도망치는 자에게는 늑대가 달려드는 잔혹한 최후를 안겨준다. 룬테라에서는 지역마다 킨드레드의 본성에 다른 의미를 부여했지만, 필멸의 존재라면 결국 진정한 죽음을 선택해야만 한다는 점은 같았다.","tags":["원거리","입문추천","정글러"]},{"name":"Trundle","koreanName":"트런들","imageId":"Trundle","positions":["정글","탑"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"쉬움","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"트런들은 몸집이 크고 교활한데다 잔인한 면모를 두루 갖춘 트롤로, 일단 트런들이 몽둥이를 들면 굴복시키지 못할 상대는 없다. 심지어 프렐요드 전역을 통틀어서 말이다. 영역 본능이 매우 강한 트런들은 자신의 영토에 발을 디딘 멍청한 자들을 쫓아가서, 거대한 얼음 정수의 몽둥이를 들고 적을 뼛속까지 얼린 채 서서히 죽어가는 모습을 보고 껄껄 웃는다.","tags":["전사","탱커","입문추천","멀티포지션","정글러"]},{"name":"Fiddlesticks","koreanName":"피들스틱","imageId":"Fiddlesticks","positions":["정글"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"어려움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"룬테라에 무시무시한 고대의 무언가가 깨어났다. 시간을 초월한 공포의 존재 피들스틱은 불안에 동요하는 인간 사회의 끝자락에 나타나 겁먹은 희생자들을 양분으로 삼는다. 앙상하고 투박한 모습의 이 생물은 삐죽삐죽한 낫을 휘두르며 공포를 거둬들이고, 살아남은 불행한 자들의 정신을 산산이 조각낸다. 까마귀 울음소리와 인간을 닮은 형상의 속삭임을 조심하라... 피들스틱이 돌아온 것이다.","tags":["마법사","서포터","고난이도","정글러"]},{"name":"Hecarim","koreanName":"헤카림","imageId":"Hecarim","positions":["정글"],"riotClass":"전사","riotSubClass":"탱커","difficulty":"보통","style":["전사","탱커"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"헤카림은 말과 인간이 한 몸인 반인반수 유령으로, 산 자들의 영혼을 끝없이 추적하는 저주를 받았다. 원래는 자존심 강한 기사로 자신의 기사단을 이끌었으나, 축복의 빛 군도에 그림자가 드리울 때 대몰락의 파괴 에너지에 휩쓸려 최후를 맞았다. 그 이후 헤카림과 기사단은 타고 있던 말과 한 몸이 되어, 검은 안개가 룬테라에 깔릴 때면 무자비한 돌격을 일삼는다. 이제 그에게 남은 쾌락이란 적을 학살하고 철갑을 두른 말발굽 아래 그 시체를 깔아뭉개는 것뿐이다.","tags":["전사","탱커","정글러"]}],"미드":[{"name":"Galio","koreanName":"갈리오","imageId":"Galio","positions":["미드"],"riotClass":"탱커","riotSubClass":"마법사","difficulty":"쉬움","style":["탱커","마법사"],"gameStyle":"defensive","visual":[],"setting":[],"description":"아스라한 빛의 도시 데마시아의 성문 밖, 거대한 석상 갈리오가 경계의 눈을 늦추지 않고 서 있다. 마법사의 공격으로부터 데마시아를 수호하기 위해 만들어진 갈리오는 강력한 마법의 힘이 그를 깨울 때까지 수십 년, 때로는 수백 년 동안 한자리에 미동도 없이 서있다. 일단 깨어나면 전투의 아찔한 스릴과 데마시아인들을 구한다는 자부심을 음미하며 1분 1초도 허투루 쓰는 법이 없다. 그러나 그가 쟁취한 승리의 향기는 결코 달콤하지만은 않다. 아이러니하게도...","tags":["탱커","마법사","입문추천"]},{"name":"Naafiri","koreanName":"나피리","imageId":"Naafiri","positions":["미드"],"riotClass":"암살자","riotSubClass":"전사","difficulty":"매우 쉬움","style":["암살자","전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"오늘도 슈리마 사막에는 우렁찬 포효가 합창곡처럼 울려 퍼진다. 게걸스러운 포식자인 모래 언덕의 사냥개들이 이 황량한 땅에서 무리지어 사냥할 권리를 두고 싸우며 울부짖는 소리다. 그중 정점에 오른 무리가 있다. 사냥개의 본능이 아니라, 고대 다르킨의 힘을 품고 움직이는 무리 말이다.","tags":["암살자","전사","입문추천"]},{"name":"Neeko","koreanName":"니코","imageId":"Neeko","positions":["미드","서포터"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"쉬움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"오랜 세월 잊힌 바스타야의 한 부족 출신인 니코는 다른 이의 모습을 빌려 어느 무리에든 뒤섞일 수 있으며, 심지어 상대의 감정을 흡수하여 적과 아군을 한눈에 구분할 수 있다. 그 누구도 니코가 어디 있는지, 정체가 무엇인지 확신할 수 없지만, 악의를 가지고 접근하는 자는 원초적 영혼 마법의 무시무시한 힘과 함께 그녀의 진정한 모습을 보게 될 것이다.","tags":["마법사","서포터","입문추천","멀티포지션"]},{"name":"Ryze","koreanName":"라이즈","imageId":"Ryze","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"보통","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"룬테라의 최고 마법사로 널리 알려진 라이즈는 산전수전을 겪으며 중차대한 임무를 수행하는 고대의 대마법사다. 가공할 마력과 무한한 체력을 보유한 그는, 태초에 무에서 세계를 창조한 원초적 마법의 파편인 룬을 찾기 위해 쉴 틈 없이 이곳저곳을 떠돌고 있다. 룬이 룬테라에 어떤 참사를 일으킬 수 있는지 알고 있기에 라이즈는 룬이 잘못된 손에 들어가지 않도록 빠짐없이 찾아야만 한다.","tags":["마법사"]},{"name":"Lux","koreanName":"럭스","imageId":"Lux","positions":["미드","서포터"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"쉬움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"럭산나 크라운가드는 데마시아 인으로, 마법 능력을 가진 자를 공포와 의심을 담은 편협한 시선으로 보는 환경에서 태어났다. 고귀한 가문의 딸이지만 빛을 자유자재로 다루는 마법력을 타고났기에 이 능력이 발각되면 추방당할 것이라는 두려움을 안고 어린 시절을 보냈다. 자신의 능력을 감추는 것만이 가문의 명예를 지키는 방법이라고 여겼지만, 낙천적이고 유연한 성격 덕분에 차츰 자신만의 재능을 인정하고 받아들였고, 이제는 조국을 위해 마법을 은밀하게 사용하고 있다.","tags":["마법사","서포터","입문추천","멀티포지션"]},{"name":"LeBlanc","koreanName":"르블랑","imageId":"Leblanc","positions":["미드"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"르블랑은 검은 장미단의 다른 구성원들조차도 본모습을 알지 못하는 신비로운 존재다. 사실 르블랑이라는 이름은 녹서스 건국 초기부터 사람들과 사건을 마음대로 홀리고 조작하던, 안색이 창백한 어느 여인이 갖고 있던 수많은 이름 중 하나에 불과하다. 르블랑은 마법으로 자신의 형체를 복제할 수 있으므로 누구에게든, 어디에든 모습을 드러낼 수 있으며 심지어 여러 장소에 동시에 존재할 수도 있다. 좀체로 남의 눈에 띄지 않고 진짜 정체를 아는 사람도 없기에...","tags":["암살자","마법사","고난이도"]},{"name":"Lissandra","koreanName":"리산드라","imageId":"Lissandra","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"보통","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"혹한의 북쪽 땅 주민들은 아주 먼 옛날부터 \'그녀\'를 두려워했다. 그녀는 순수한 냉기를 왜곡시켜 어둠의 힘으로 부리는 마법을 구사했으며, 날카로운 얼음으로 자신에 대적하는 적들을 모조리 꿰뚫어 버리거나 으스러뜨렸다. 얼마나 무시무시하고 막강한 힘이었는지! 사람들은 그녀의 본명을 언급하는 것마저 꺼려 \'얼음 마녀\'라는 별명으로 그녀를 칭하곤 했다. 그러나 진정 두려운 것은 그녀의 힘이 아니라 위험한 계획이었다. 이 사악한 마녀의 이름은 리산드라...","tags":["마법사"]},{"name":"Malzahar","koreanName":"말자하","imageId":"Malzahar","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"보통","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"말자하는 모든 생명체를 하나로 결합시키겠다는 사명에 전심전력을 바치는 예언자다. 그는 근래 룬테라를 덮치기 시작한 공허야말로 룬테라를 구원하는 길이라고 진심으로 믿고 있다. 모래 가득한 슈리마의 황무지에서, 말자하는 머릿속에서 울리는 속삭임이 이끄는 대로 따라간 끝에 이케시아에 다다랐다. 이제는 폐허가 되어버린 이케시아 한가운데에서 그는 공허의 어두운 심장부를 들여다보았고, 새로운 힘과 목적을 부여받았다. 이제 말자하는 자신을 목자로 칭한다. 그에게...","tags":["마법사"]},{"name":"Mel","koreanName":"멜","imageId":"Mel","positions":["미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"쉬움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"멜 메다르다는 한때 녹서스에서 손꼽히는 세도가 중 하나였던 메다르다 가문의 후계자로 추정된다. 겉보기에는 우아한 귀족이지만 그 이면에는 자신이 만나는 모든 사람의 모든 것을 파악하는 노련한 정치가가 있다. 수수께끼에 싸인 검은 장미단과 조우한 후, 멜은 어머니의 기만이 얼마나 깊은지 알아냈고 처음으로 자신의 통제력을 벗어난 상황에 직면했다. 각성하여 마법의 힘을 손에 넣은 멜은 답을 찾아 고향으로 향했다. 멜 내면의 빛을 길들이고자 하는 이는 여전히...","tags":["마법사","서포터","입문추천"]},{"name":"Veigar","koreanName":"베이가","imageId":"Veigar","positions":["미드","서포터"],"riotClass":"마법사","riotSubClass":null,"difficulty":"보통","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"밴들 시티에 사는 자유로운 영혼, 흑마법의 대가인 베이가는 오직 열정 하나만으로 필멸자는 감히 엄두조차 못 낼 힘을 손에 넣었다. 베이가는 수 천 년 동안 감춰졌던 신비로운 문헌을 탐독하여 요들 마법의 한계를 뛰어넘고 싶어했지만, 다른 요들들은 끝없는 호기심으로 우주의 수수께끼만을 고집스럽게 탐구하는 베이가를 얕잡아 보곤 했다. 사실 베이가는 스스로를 궁극의 악한 존재라고 여기지만, 마음 깊은 곳에는 타고난 도덕성이 숨어 있다. 그래서 베이가의 진짜...","tags":["마법사","멀티포지션"]},{"name":"Vex","koreanName":"벡스","imageId":"Vex","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"쉬움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"그림자 군도의 검은 심장에서 고독한 요들 하나가 망령의 안개 속을 터덜터덜 걸으며 그 어두운 불행을 즐긴다. 청소년 특유의 끝없는 고뇌와 강력한 그림자를 달고 다니는 벡스는 혐오스러운 활기로 가득한 일반 세계와 거리를 두고 자신이 만들어 낸 우울함 속에서 살아간다. 야심은 부족하지만 침울한 분위기로 사전에 모든 침입자를 막으며 순식간에 색깔과 행복을 없앤다.","tags":["마법사","입문추천"]},{"name":"Vladimir","koreanName":"블라디미르","imageId":"Vladimir","positions":["미드","탑"],"riotClass":"마법사","riotSubClass":"전사","difficulty":"보통","style":["마법사","전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"필멸자의 피를 갈구하고 탐닉하는 블라디미르는 녹서스 건국 초기부터 제국에서 벌어지는 각종 사건에 영향을 끼쳤다. 수명을 비정상적으로 늘린 데다가, 피를 제어하는 능력을 이용해 다른 이들의 정신과 육체를 제 것인 듯 손쉽게 통제한다. 블라디미르의 이 능력은 녹서스 귀족 사회의 호화찬란한 살롱에서는 광적인 추종자 세력을 만드는 정도로 그치지만, 어두운 뒷골목에서는 적의 피를 마지막 한 방울까지 말려 버리는 데 쓰인다.","tags":["마법사","전사","멀티포지션"]},{"name":"Viktor","koreanName":"빅토르","imageId":"Viktor","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"어려움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"과거의 모습을 벗어던지고 완전한 생체기계로 변모한 빅토르는 영광스러운 진화를 받아들이고 추종자들의 구세주와 같은 존재가 되었다. 감정을 제거하면 고통도 제거될 것이라는 논리로 자신의 인간성을 희생한 빅토르는 이제 온 세상에 마공학 핵의 진리를 전파하고자 한다. 설령 세상이 그 혜택을 이해하지 못하더라도 상관없다. 결국 이 비전의 대가에게 폭력이란 궁극적인 상황에서 균형을 잡는 데 필요한 변수일 뿐이니까.","tags":["마법사","고난이도"]},{"name":"Sylas","koreanName":"사일러스","imageId":"Sylas","positions":["미드","정글"],"riotClass":"마법사","riotSubClass":"암살자","difficulty":"쉬움","style":["마법사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"데마시아의 빈민 구역, 드레그본에서 자란 사일러스는 위대한 도시의 어두운 면을 상징한다. 숨겨진 마력을 탐지하는 능력을 지닌 사일러스는 어렸을 때 마력척결관들의 눈에 띄지만, 결국 마력척결관을 상대로 마력을 사용하면서 감옥에 갇힌다. 감옥에서 탈출한 사일러스는 이제 불굴의 혁명가로 살며 한때 자신이 섬겼던 왕국을 파괴하기 위해 주변 사람들의 마법을 이용한다. 추방자들로 이루어진 사일러스의 마법사 군단은 날로 그 기세를 더해가는 듯 보인다.","tags":["마법사","암살자","입문추천","멀티포지션","정글러"]},{"name":"Syndra","koreanName":"신드라","imageId":"Syndra","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"어려움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"아이오니아의 무시무시한 마법사 신드라는 믿을 수 없을 정도로 강대한 힘을 자유자재로 다룬다. 어렸을 때부터 엄청난 마법을 제멋대로 쓰고 다니는 바람에 마을 장로들을 아연실색하게 만들었다. 신드라는 절제를 배우도록 외딴곳으로 보내졌지만, 결국 소위 스승이라는 자가 그동안 자신의 힘을 억제했다는 사실을 알게 되었다. 신드라는 배신감과 상처를 어둠의 구체로 만들어 자신을 통제하려는 자는 모조리 파멸시키겠다고 마음먹었다.","tags":["마법사","고난이도"]},{"name":"Ahri","koreanName":"아리","imageId":"Ahri","positions":["미드"],"riotClass":"마법사","riotSubClass":"암살자","difficulty":"쉬움","style":["마법사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"영혼 세계의 마법과 선천적으로 연결된 아리는 먹잇감의 감정을 조종하고 정수를 집어삼킬 수 있는 여우 모습의 바스타야로, 영혼을 먹어 치울 때마다 그 안에 담긴 지혜와 기억의 편린을 받아들인다. 강력하면서도 불안정한 포식자였던 아리는 이제 조상들의 흔적을 찾아 세상을 여행하며 지금껏 훔친 기억을 버리고 스스로 자신만의 추억을 쌓으려 한다.","tags":["마법사","암살자","입문추천"]},{"name":"Aurelion Sol","koreanName":"아우렐리온 솔","imageId":"AurelionSol","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"보통","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"아우렐리온 솔은 천상의 경이로운 별들을 손수 빚어 한때 텅 비어있던 광활한 우주를 수놓았다. 그러나 이제 그는 속임수로 자신을 복종시킨 우주 제국의 명령에 따라 자신의 막강한 힘을 발휘해야 하는 처지가 되었다. 별을 만들던 때로 돌아가려는 열망에 불타는 아우렐리온 솔은 자신의 자유를 되찾기 위해서라면 자신의 창조물인 별들을 하늘에서 없앨 각오마저 되어 있다.","tags":["마법사"]},{"name":"Azir","koreanName":"아지르","imageId":"Azir","positions":["미드"],"riotClass":"마법사","riotSubClass":"원거리","difficulty":"어려움","style":["마법사","원거리"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"불멸을 꿈꾸던 고대 슈리마의 거만한 황제, 아지르. 그의 오만은 생애 최전성기에 그를 배반과 죽음으로 몰아 넣었다. 그 후 수천 년이 흘렀고, 아지르는 가공할 힘을 지닌 초월체로 다시 태어났다. 사막 아래 묻혀 있던 그의 도시가 지표면 위로 솟아 오르는 장관을 목도하며 아지르는 슈리마 제국의 옛 영광을 되살리겠다고 다짐한다.","tags":["마법사","원거리","고난이도"]},{"name":"Akali","koreanName":"아칼리","imageId":"Akali","positions":["미드","탑"],"riotClass":"암살자","riotSubClass":null,"difficulty":"보통","style":["암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"킨코우 결사단과 그림자의 권이라는 지위를 버린 아칼리는 아이오니아인들에게 필요한 강력한 무기가 되어 홀로 싸우고 있다. 스승 쉔의 가르침을 잊지 않은 채 아이오니아의 적을 하나씩 암살하기로 맹세했다. 아칼리의 살행은 은밀할지 모르나 그녀의 메시지는 대륙 전체를 뒤흔든다. \'\'경외하라. 나는 섬기는 이 없는 암살자다.\'\'","tags":["암살자","멀티포지션"]},{"name":"Akshan","koreanName":"아크샨","imageId":"Akshan","positions":["미드"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"쉬움","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"상반신을 드러낸 아크샨은 위험에 직면하면 눈썹을 치켜올리며 당당한 카리스마, 정의로운 복수심으로 악과 맞서 싸운다. 전투에서 뛰어난 은신술을 발휘하며 적의 눈을 피한 후 제일 예기치 못한 순간 다시 모습을 드러낸다. 불타는 정의감과 죽음을 되돌리는 전설적인 무기로 룬테라의 수많은 악한들이 저지른 잘못을 바로잡으며 \'멍청이가 되지 말자\'라는 자신만의 도덕적 기준에 따라 살아간다.","tags":["원거리","암살자","입문추천"]},{"name":"Annie","koreanName":"애니","imageId":"Annie","positions":["미드","서포터"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"보통","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"순수함 속에 아이답지 않은 위험한 모습을 간직한 애니는 불을 다루는 강력한 마법사다. 녹서스 북부의 산속에서 그림자처럼 숨어 지내면서도 그녀의 마법은 두각을 드러냈다. 아기였을 때부터 예측할 수 없는 감정의 분출과 함께 타고난 화염 친화성을 보인 애니는 곧 이런 \'재주\'를 제어할 수 있게 되었다. 그 중 사랑하는 곰 인형 \'티버\'를 열렬한 수호자로 소환하는 것을 가장 좋아한다. 끝 모를 동심을 품은 애니는 언제나 어두운 숲을 거닐며 같이 놀 누군가를...","tags":["마법사","서포터","멀티포지션"]},{"name":"Anivia","koreanName":"애니비아","imageId":"Anivia","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"매우 어려움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"애니비아는 삶과 죽음, 부활을 끊임없이 반복하며 프렐요드를 지키는 날개 달린 반신이다. 매섭기 짝이 없는 얼음과 칼바람에서 태어났으며, 이런 자연의 힘을 자유자재로 이용하여 자신의 고향땅을 어지럽히려 드는 무모한 자들을 응징한다. 혹한의 북쪽에 터를 잡은 부족들에게 애니비아는 그들을 이끌고 보호하는 자애로운 존재로, 희망의 상징이자 크나큰 변화를 가져오는 징조로 숭배를 받는다. 애니비아는 전장에서 죽음을 두려워하지 않고 전력을 다해 싸운다. 자신을...","tags":["마법사","고난이도"]},{"name":"Yasuo","koreanName":"야스오","imageId":"Yasuo","positions":["미드"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"매우 어려움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"굳은 결의를 품은 아이오니아의 검객 야스오는 날렵한 검술과 바람을 자유로이 다루는 능력으로 적을 쓰러뜨린다. 젊은 시절, 자부심으로 가득 찼던 야스오는 스승을 살해한 누명을 쓰게 되고, 결백을 증명할 길이 없는 상황에서 급기야는 자신을 보호하기 위해 친형까지 죽음으로 이끌게 된다. 스승을 살해한 진범이 결국 밝혀졌지만, 지금도 야스오는 자신의 검을 인도하는 바람에만 의존한 채 고향 아이오니아를 배회하고 있다. 과거의 자신을 아직 용서하지 못한 채로.","tags":["전사","암살자","고난이도"]},{"name":"Aurora","koreanName":"오로라","imageId":"Aurora","positions":["미드","탑"],"riotClass":"마법사","riotSubClass":"암살자","difficulty":"쉬움","style":["마법사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"태어난 순간부터 오로라는 영혼 세계와 물질 세계를 넘나드는 특별한 능력으로 삶의 길을 찾았다. 영혼 세계의 주민들에 대해 더 알고 싶었던 오로라는 자신의 고향을 떠났고, 시간 속에 뒤틀리고 길을 잃어 방황하는 반신을 만났다. 그의 절박함을 목격한 오로라는 자신의 거친 친구가 잊어버린 자아를 되찾도록 도와줄 방법을 찾기로 결심했고 프렐요드의 가장 먼 곳으로 여정을 떠났다.","tags":["마법사","암살자","입문추천","멀티포지션"]},{"name":"Orianna","koreanName":"오리아나","imageId":"Orianna","positions":["미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"보통","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"오리아나는 한 때 살아있는 육신을 가진 호기심 많은 소녀였지만, 이제는 전체가 시계태엽 장치로 만들어진 놀라운 기술의 산물이다. 오리아나는 자운 남부지방에서 사고를 당한 후 매우 위태로운 상황에 처했고, 다쳐서 움직일 수 없는 신체의 부분 부분이 정교한 인공 신체로 교체되었다. 오리아나는 자신을 보호하는 친구 역할을 해 주는 강력한 황동 구체와 함께, 이제 필트오버를 비롯해 온 세상에 있는 불가사의를 자유롭게 탐험한다.","tags":["마법사","서포터"]},{"name":"Yone","koreanName":"요네","imageId":"Yone","positions":["미드","탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"어려움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"생전에 야스오의 이부형제였던 요네는 마을 검술 학교에서 촉망받는 학생이었다. 그러나 형제의 손에 죽음을 맞이한 후 영혼 세계의 악령에 쫓기자 악령의 검으로 악령을 죽일 수밖에 없었다. 악령의 가면을 써야 하는 저주를 받게 된 요네는 자신이 어떤 존재가 되었는지 알아내기 위해 쉬지 않고 그 악령과 같은 존재들을 뒤쫓는다.","tags":["전사","암살자","고난이도","멀티포지션"]},{"name":"Zaahen","koreanName":"자헨","imageId":"Zaahen","positions":["미드"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"매우 쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"신성과 불경한 힘을 모두 지닌 추락한 신 자헨은 자신을 집어삼키려는 타락에 맞서 싸우며, 동족 다르킨을 사냥합니다. 광기를 피해 스스로 글레이브 속에 자신을 가두었던 자헨은 이제 자유의 몸이 되어 고결한 마음과 잔혹한 의지로 움직입니다. 내면에서 벌어지는 영원한 전쟁을 버텨내는 한, 자헨은 룬테라를 파멸로 이끄는 모든 존재 위에 우뚝 서게 될 것입니다.","tags":["전사","암살자","입문추천"]},{"name":"Zed","koreanName":"제드","imageId":"Zed","positions":["미드"],"riotClass":"암살자","riotSubClass":null,"difficulty":"보통","style":["암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"제드는 극도로 무자비하고 인정사정없는 인물로, 녹서스 침공군을 몰아내기 위해 아이오니아의 전통 마법과 무술을 집약시킨다는 의도로 설립한 그림자단의 수장이다. 아이오니아 전쟁 중 제드는 녹서스에게 이기고 싶다는 간절한 마음에서 그림자 비급의 봉인을 해제해 버렸다. 그 사악한 비급은 강력한 만큼이나 위험하고, 사용자를 타락의 길로 빠뜨리는 것이었다. 하지만 제드는 아랑곳하지 않고 모든 금단의 비술을 익혔다. 자신의 국가에, 아니면 자신이 만든 그림자단에...","tags":["암살자"]},{"name":"Zoe","koreanName":"조이","imageId":"Zoe","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"쉬움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"상상력과 변화의 화신인 장난꾸러기 조이는 타곤의 우주 전령으로, 세계를 뒤흔드는 중요한 사건들을 알린다. 조이는 존재만으로도 현실 세계를 지배하는 불가사의한 수학 원리를 왜곡하고, 가끔은 아무런 악의나 노력 없이도 대재앙을 일으킨다. 이것이 그녀가 자신의 의무에 경쾌하고도 태연하게 임하는 이유일지도 모른다. 조이는 장난을 치고 인간들을 골탕 먹이는 등 즐겁게 보낼 시간이 많다. 그녀를 만나면 매우 즐겁고 삶을 긍정적으로 바라보게 될 수도 있지만...","tags":["마법사","입문추천"]},{"name":"Kassadin","koreanName":"카사딘","imageId":"Kassadin","positions":["미드"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"이 세계에서도 가장 어두운 곳을 불타는 검을 휘둘러 헤쳐나가는 카사딘은 자신에게 주어진 시간이 많지 않음을 잘 알고 있다. 원래 슈리마 구석구석 가보지 않은 곳이 없는 여행 안내자이자 모험가였던 그는 슈리마 남쪽의 평화로운 부족 마을에서 가정을 꾸리고 살았다. 하지만 어느 날, 그가 살던 곳을 공허가 덮쳐 집어삼켰다. 카사딘은 복수를 맹세했고, 신비로운 유물과 금지된 기술을 닥치는 대로 조합하여 앞으로의 투쟁에 쓸 무기를 만들었다. 황무지 이케시아를...","tags":["암살자","마법사","고난이도"]},{"name":"Cassiopeia","koreanName":"카시오페아","imageId":"Cassiopeia","positions":["미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"매우 어려움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"카시오페아는 자신의 사악한 의지대로 상대를 조종하는 치명적인 피조물이다. 녹서스의 명망 높은 뒤 쿠토 가에서 가장 아름다운 미모를 자랑하던 막내딸, 카시오페아는 고대의 힘을 찾아 슈리마 아래에 있는 지하묘실 깊은 곳으로 모험을 떠났다. 그곳에서 그녀는 소름끼치는 묘실의 수호령에게 물렸고, 몸에 독이 퍼져 독사와도 같은 포식자로 변했다. 카시오페아는 이제 밤의 장막에 숨어 교활하고 날렵하게 움직이며 사악한 시선으로 적들을 석화시킨다.","tags":["마법사","고난이도"]},{"name":"Katarina","koreanName":"카타리나","imageId":"Katarina","positions":["미드"],"riotClass":"암살자","riotSubClass":"마법사","difficulty":"어려움","style":["암살자","마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"카타리나는 단호한 판단력과 치명적인 전투 능력을 지닌 녹서스의 특급 암살자이다. 전설적인 명성을 자랑하는 뒤 쿠토 장군의 장녀로 태어난 카타리나는 방심한 적을 신속하게 암살하는 데에 뛰어난 재능을 보였다. 그녀는 자신의 불타는 야망 때문에 아군을 위험에 빠뜨리면서까지 방비를 강화한 적을 노리기도 했다. 하지만 임무가 아니더라도 카타리나는 주저없이 톱날 단검의 돌풍을 일으켜 마땅히 쓰러뜨려야 할 적을 처치할 것이다.","tags":["암살자","마법사","고난이도"]},{"name":"Corki","koreanName":"코르키","imageId":"Corki","positions":["미드"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"요들 비행기 조종사 코르키는 다른 어떤 것보다 좋아하는 두 가지가 있다. 바로 비행과 멋들어진 콧수염이다. 좋아하는 순서대로 나열한 것은 아니지만. 코르키는 밴들 시티를 떠난 후 필트오버에 정착하며 찾아낸 경이로운 비행기와 사랑에 빠졌다. 코르키는 비행장치를 개발하기 위해 혼신의 노력을 쏟았고, 시끄러운 뱀 편대라 불리는 베테랑 공군 정예 부대를 이끌게 되었다. 포화 속에서도 평정심을 잃지 않으며 제2의 고향의 창공을 누비는 코르키에게 마음껏 미사일...","tags":["원거리","마법사"]},{"name":"Qiyana","koreanName":"키아나","imageId":"Qiyana","positions":["미드"],"riotClass":"암살자","riotSubClass":null,"difficulty":"어려움","style":["암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"키아나는 정글 도시 이샤오칸에서 윤 탈의 왕좌에 오르기 위해 무자비한 계획을 세우고 있다. 부모님의 왕위 계승 서열 중 가장 아래인 키아나는 당당한 자신감과 전례 없는 원소 마법 능력을 갖춘 인재로, 앞을 가로막는 자는 누구든 용서하지 않는다. 키아나는 대지 자체를 자유자재로 조종할 수 있으며, 자신을 이샤오칸 역사상 가장 뛰어난 원소술사로 여긴다. 그렇기에 자신에게 일개 도시가 아닌 제국을 지배할 자격이 있다고 믿는다.","tags":["암살자","고난이도"]},{"name":"Talon","koreanName":"탈론","imageId":"Talon","positions":["미드","정글"],"riotClass":"암살자","riotSubClass":null,"difficulty":"보통","style":["암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"탈론은 음지에서 암약하는 무자비한 자객이다. 불의의 일격을 가하는 데에도, 이상한 낌새가 느껴지기도 전에 자취를 감추는 데도 능하다. 거칠기 짝이 없는 녹서스의 거리에서 싸우고, 상대를 처치하고, 도둑질을 하면서 살아남았고 위험한 존재라는 명성을 쌓았다. 악명이 자자한 뒤 쿠토 가문에 발탁된 뒤로는 녹서스 제국의 명을 받들어 적의 지도자, 대장, 영웅은 물론이고, 감히 자신이 섬기는 주인의 심기를 거스르는 녹서스 인마저도 종횡무진 암살하고 있다.","tags":["암살자","멀티포지션","정글러"]},{"name":"Taliyah","koreanName":"탈리야","imageId":"Taliyah","positions":["미드","정글"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"쉬움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"슈리마의 떠돌이 마법사 탈리야는 10대의 호기심과 어른으로서의 책임 사이에서 괴로워한다. 탈리야는 자신 안에서 커져 가는 힘의 본질을 깨닫기 위해 발로란 전역을 누빈 끝에, 최근에는 자신의 부족을 보호하기 위해 돌아왔다. 탈리야의 여린 마음을 약점으로 착각한 사람들은 호되게 대가를 치렀다. 탈리야의 천진난만한 모습 뒤에는 산도 움직이는 불굴의 의지와 대지도 흔드는 강인한 정신이 있기 때문이다.","tags":["마법사","서포터","입문추천","멀티포지션","정글러"]},{"name":"Twisted Fate","koreanName":"트위스티드 페이트","imageId":"TwistedFate","positions":["미드"],"riotClass":"마법사","riotSubClass":"원거리","difficulty":"어려움","style":["마법사","원거리"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"트위스티드 페이트는 악명 높은 카드의 달인이자 사기꾼이다. 뛰어난 도박 실력과 타고난 매력으로 발로란 어디에서나 부자와 어리석은 자들 모두에게 감탄과 원한을 한 몸에 사는 주인공이다. 매사에 진지한 법이 없고, 태평하고 으스대는 얼굴에는 비웃는 듯한 미소마저 감돈다. 트위스티드 페이트의 소매에는 늘 비장의 카드가 숨겨져 있으니까.","tags":["마법사","원거리","고난이도"]},{"name":"Fizz","koreanName":"피즈","imageId":"Fizz","positions":["미드"],"riotClass":"암살자","riotSubClass":"전사","difficulty":"보통","style":["암살자","전사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"바다와 육지에서 살 수 있는 요들족 피즈는 빌지워터를 둘러싼 산호초에서 살고 있다. 종종 미신을 믿는 선장들이 바다에 바치는 돈을 주워 돌려주기도 하지만, 아무리 신경질적인 뱃사람들이라도 피즈를 화나게 할 만큼 어리석지는 않다. 이 미끈거리는 생명체를 얕잡아본 사람들이 어떻게 되었는지에 대해 수많은 이야기가 전해지고 있기 때문이리라. 이따금 변덕스러운 바다 정령으로 오해받기도 하는 피즈는 바닷속 깊은 곳에 사는 괴물을 부릴 수 있으며, 적과 아군을...","tags":["암살자","전사"]},{"name":"Heimerdinger","koreanName":"하이머딩거","imageId":"Heimerdinger","positions":["미드","탑","서포터"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"어려움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"괴짜 성향이 다분한 세실 B. 하이머딩거 교수는 세계에서 가장 혁신적인 인재로 손꼽히며 모든 이의 존경을 받는 발명가다. 필트오버 의회에서 최장기간 재임한 의원인 그는 진보를 향한 도시의 끝없는 욕망이 불러온 최고의 결과와 최악의 결과를 모두 목격했다. 그럼에도 뛰어난 과학자이자 교육자인 하이머딩거 교수는 자신이 만든 특이한 장치로 타인의 삶을 개선하는 일을 게을리하지 않는다.","tags":["마법사","서포터","고난이도","멀티포지션"]},{"name":"Hwei","koreanName":"흐웨이","imageId":"Hwei","positions":["미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"어려움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"음울한 화가 흐웨이는 찬란한 그림을 그려 아이오니아의 범죄자에게 맞서고, 희생자들에게는 위안을 선사한다. 우울한 겉모습 아래에는 갈가리 찢어진 감성이 자리를 잡고 있다. 그리고 자신의 상상력에서 비롯된 생생한 환상과 끔찍한 사원 학살극의 기억은 흐웨이를 쫓아다니며 괴롭힌다. 흐웨이의 목표는 이 명암을 이해하고, 종국에는 자신을 찢어발긴 예술가에게 닿는 것이다. 붓과 팔레트에서 피어나는 가능성이 흐웨이의 앞길을 인도한다. 그 끝이 절망의 극복일지...","tags":["마법사","서포터","고난이도"]}],"원딜":[{"name":"Nilah","koreanName":"닐라","imageId":"Nilah","positions":["원딜"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"매우 어려움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"멀리 떨어진 땅에서 온 고행의 전사, 닐라는 세계에서 가장 위협적이고 거대한 상대를 찾아 도전하고 파괴한다. 오랫동안 갇혀 있던 기쁨의 악마를 만나 힘을 얻은 그녀에게 멈추지 않는 기쁨 외에 다른 감정은 없다. 자신의 막강한 힘을 위한 사소한 대가인 셈이다. 악마의 물을 막강한 힘을 지닌 칼날로 바꾼 닐라는 오래전에 잊힌 고대의 위협에 맞서 싸운다.","tags":["전사","암살자","고난이도"]},{"name":"Draven","koreanName":"드레이븐","imageId":"Draven","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"어려움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"녹서스에서는 경기장에서 피를 흘리며 싸우고 힘을 겨루는 전사들이 있다. 검투사로 알려진 이들 중 드레이븐만큼 많은 환호를 받은 전사는 없었다. 전직 군인인 드레이븐은 극적으로 회전 도끼를 던지는 화려하고 독보적인 기술에 관중들이 환호한다는 것을 알아차렸다. 드레이븐은 요란하고도 완벽한 구경거리를 만들어내는 자신의 기술에 도취되어, 드레이븐이라는 이름을 녹서스 제국에 길이 남기기 위해 누구든 쓰러뜨리겠다고 다짐했다.","tags":["원거리","고난이도"]},{"name":"Lucian","koreanName":"루시안","imageId":"Lucian","positions":["원딜"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"보통","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"빛의 감시자 루시안은 악령과 망령을 사냥하는 음울한 사냥꾼으로, 언데드들을 끈질기게 추적하여 유물 쌍권총으로 말살시켜 버린다. 악령 쓰레쉬의 손에 아내를 잃고 복수만을 노렸지만, 아내가 살아 돌아온 후에도 루시안의 분노는 수그러들지 않았다. 외골수에다 자비를 모르는 루시안은 검은 안개가 끝없이 내뿜는 공포의 악령들에게서 살아 있는 존재들을 지키기 위해서라면 어떤 일도 서슴지 않을 것이다.","tags":["원거리","암살자"]},{"name":"Miss Fortune","koreanName":"미스 포츈","imageId":"MissFortune","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"매우 쉬움","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"빌지워터의 선장 사라 포츈은 미모로도 유명하지만 무자비한 일처리 때문에 공포의 대상이기도 하다. 틀로 찍어낸 듯 똑같은 빌지워터의 범죄자들 사이에서 그녀는 단연 돋보이는 존재다. 어릴 적 자신의 가족이 해적왕 갱플랭크에게 살해당하는 것을 목격했고, 세월이 흐른 후 갱플랭크가 타고 있던 기함을 불태우는 것으로 잔혹한 복수극을 완성했다. 사라 포츈을 과소평가했다가는 그 매력에 가려진 예측불허의 실력에 기겁을 하거나... 배에 총알 구멍이 날 수도 있다.","tags":["원거리","마법사","입문추천"]},{"name":"Varus","koreanName":"바루스","imageId":"Varus","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"매우 쉬움","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"바루스는 고대 다르킨 중 한 명으로, 적이 거의 미쳐 버릴 정도로 고통을 준 뒤에야 화살을 날려 숨통을 끊는 것을 즐기는 치명적인 암살자이다. 다르킨 전쟁 말미에는 갇히는 신세가 되었으나 몇백 년 후 아이오니아 사냥꾼 두 명의 육신을 빼앗는 방식으로 탈출했다. 두 사냥꾼은 자신들도 모르게 바루스를 풀어준 형국이 되었고 이제는 그의 육신이 되어 바루스의 정기가 갇힌 활을 짊어질 수밖에 없는 운명이 되었다. 바루스는 이제 잔인한 복수를 위해 자신을 가둔...","tags":["원거리","마법사","입문추천"]},{"name":"Vayne","koreanName":"베인","imageId":"Vayne","positions":["원딜","탑"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"어려움","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"가차 없는 괴물 사냥꾼 샤우나 베인은 가족을 몰살한 마녀를 찾아 죽이기로 맹세했다. 손목에 장착된 석궁과 복수심에 불타는 마음으로 무장한 베인이 진정 행복할 때는 오직 그림자 속에서 질풍처럼 은화살을 날려 흑마법을 연구하는 자나 흑마법이 만들어낸 창조물을 벨 때뿐이다.","tags":["원거리","암살자","고난이도","멀티포지션"]},{"name":"Samira","koreanName":"사미라","imageId":"Samira","positions":["원딜"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"보통","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"사미라는 죽음의 순간에서도 눈 하나 깜짝하지 않는다. 그저 어디에 있든 도전을 찾아 헤맬 뿐이다. 어린 시절 슈리마의 고향이 파괴된 후로 녹서스에서 자신의 길을 찾았고, 그때부터 화려하면서도 무모한 방식으로 위험한 임무를 탁월하게 수행하는 자라는 명성을 쌓았다. 검은 화약을 담은 권총과 자신을 위해 정교히 만들어진 칼날과 함께, 사미라는 생사의 상황에서 빠른 몸놀림과 재능으로 그녀의 앞을 가로막는 자들을 모두 제거한다.","tags":["원거리","암살자"]},{"name":"Smolder","koreanName":"스몰더","imageId":"Smolder","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"녹서스 변경 부근의 깎아지른 절벽 지대에서 한 어린 용이 어미 용의 냉엄한 시선 아래 카마보르 황실의 용 혈통을 이을 후계자 수업을 받고 있다. 천성 자체가 쾌활한 스몰더는 하루라도 빨리 어른이 될 날을 꿈꾸면서, 오늘도 몰라보게 성장하는 제 능력을 시험할 구실을 찾아다니는 중이다. 아직 좀 어리긴 하지만, 스몰더는 어떤 것이든지 불에 타기만 한다면 가볍게 태워버릴 수 있는 능력을 지니고 있다.","tags":["원거리","마법사"]},{"name":"Sivir","koreanName":"시비르","imageId":"Sivir","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"쉬움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"시비르는 슈리마 사막에서 활동하는 보물 사냥꾼이자 용병 대장이다. 몸값은 입이 떡 벌어질 정도로 비싸지만 전투를 벌이는 족족 이겨 몸값에 걸맞은 솜씨로 명성이 자자하다. 대담무쌍한 성격에 원대한 야심까지 겸비한 시비르. 그녀는 위험하기 짝이 없는 슈리마의 묘역에서 진귀한 보물을 찾으며 남다른 자부심을 느낀다. 의뢰인에게서 두둑한 대가를 챙기는 것은 물론이다. 하지만 슈리마에 고대의 존재들이 귀환하면서 시비르도 운명의 갈림길에 서게 된다.","tags":["원거리","입문추천"]},{"name":"Aphelios","koreanName":"아펠리오스","imageId":"Aphelios","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"매우 어려움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"달그림자에서 나타나는 아펠리오스는 음울한 적막 속에서 적을 쓰러뜨린다. 정확한 조준과 총성만이 그의 목소리를 대신한다. 독에 중독되어 말을 할 수 없게 되었지만 머나먼 사원에 있는 쌍둥이 여동생 알룬이 그를 인도하며 월석의 힘을 그의 손에 쥐여 준다. 하늘에서 달이 빛나는 한 아펠리오스는 결코 혼자가 아니다.","tags":["원거리","고난이도"]},{"name":"Ashe","koreanName":"애쉬","imageId":"Ashe","positions":["원딜"],"riotClass":"원거리","riotSubClass":"서포터","difficulty":"쉬움","style":["원거리","서포터"],"gameStyle":"control","visual":[],"setting":[],"description":"아바로사 부족의 냉기의 화신이자 전쟁의 어머니인 애쉬는 북방에서 가장 규모가 큰 군단을 이끌고 있다. 절제력이 뛰어나고 총명한데다 이상주의적인 면을 갖추고 있지만 지도자라는 역할을 부담스러워하기도 한다. 고대 마법의 힘이 흐르는 혈통을 이어받았기에 얼음 정수의 활을 무기로 사용할 수 있다. 아바로사 부족민들은 애쉬가 전설 속 영웅 아바로사 여왕의 화신이라고 굳게 믿으며, 애쉬는 이들과 함께 먼 옛날 자신의 부족이 살았던 영토를 되찾아 다시 한 번...","tags":["원거리","서포터","입문추천"]},{"name":"Yunara","koreanName":"유나라","imageId":"Yunara","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"쉬움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"유나라는 아이오니아에 대한 변함없는 헌신으로, 수 세기 동안 영혼 세계에 칩거하며 전설적인 킨코우 유물인 에이온 에르나를 다루는 법을 연마했습니다. 많은 것을 희생했음에도, 이 땅에서 불화와 갈등을 몰아내겠다는 유나라의 맹세는 그 신념만큼이나 굳건했습니다. 그러나 그녀를 기다리는 세상과, 다시금 그림자를 드리운 고대의 위협은 그 결의를 극한까지 시험할 것입니다.","tags":["원거리","입문추천"]},{"name":"Ezreal","koreanName":"이즈리얼","imageId":"Ezreal","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"마법에 타고난 재능을 가진 멋진 모험가 이즈리얼은 오래전에 사라진 지하 묘지를 탐험하고 고대 저주에 맞서 싸우며 힘든 역경을 손쉽게 극복한다. 끝없는 용기와 무모함을 지닌 그는 어떠한 상황에서도 즉흥적으로 헤쳐나가는 것을 선호한다. 기지를 발휘할 때도 있지만, 대부분은 파괴적이고 불가사의한 폭발을 일으키는 슈리마의 신비한 장갑에 의지한다. 한 가지 분명한 사실은 이즈리얼이 가는 곳에 말썽이 있다는 것이다. 혹은 눈앞에 있거나. 아마 사방에 있을지도...","tags":["원거리","마법사"]},{"name":"Xayah","koreanName":"자야","imageId":"Xayah","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"쉬움","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"바스타야 혁명을 일으키고 싶어하는 자야는 치명적인 정확성을 자랑하는 전사이다. 민첩한 몸놀림과 간교할 정도로 예리한 두뇌를 갖추었고, 칼날보다 날카로운 깃털로 자신을 막아서는 것은 모조리 베어버린다. 한때는 점점 수가 줄어들고 있는 바스타야 종족을 구해내기 위해 혼자만의 전쟁을 수행했으나, 이제는 동지이자 연인인 라칸과 늘 함께 싸운다. 둘은 바스타야 종족을 보호하고 먼 옛날 바스타야 종족이 누리던 영광을 되찾기 위해 노력하고 있다.","tags":["원거리","입문추천"]},{"name":"Zeri","koreanName":"제리","imageId":"Zeri","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"보통","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"자운 노동자 계층 출신의 고집 세고 활발한 제리는 전기 마법으로 자신의 힘과 손수 제작한 총을 충전한다. 그녀의 불안정한 힘은 감정을 반영하고 그 불꽃은 번개처럼 빠른 삶을 닮았다. 동정심 많은 제리는 가족과 고향에 대한 애정으로 싸움에 임한다. 가끔 도우려는 의지가 강해 역효과를 일으키기도 하지만, 이웃을 위해 싸울 때 그들 또한 함께한다는 사실을 믿고 있다.","tags":["원거리"]},{"name":"Ziggs","koreanName":"직스","imageId":"Ziggs","positions":["원딜","미드"],"riotClass":"마법사","riotSubClass":null,"difficulty":"쉬움","style":["마법사"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"거대한 폭탄을 사랑하는 직스는 폭탄만큼이나 화끈한 성미를 지닌 요들이다. 필트오버에서 어느 발명가를 돕는 조수로 일하다가, 반복되는 일상에 싫증을 느끼던 중 파란 머리의 미친 폭탄광 징크스와 친구가 되었다. 어느 날 필트오버에서 요란스러운 밤을 보낸 후, 직스는 징크스의 조언을 듣고 자운으로 향했다. 자운은 직스에게 천국이다. 제일 좋아하는 폭탄을 마음껏 터뜨리고 무엇이든 내키는 대로 폭발시키며, 자운 시민뿐 아니라 화공 남작들까지 공포에 질리게...","tags":["마법사","입문추천","멀티포지션"]},{"name":"Jhin","koreanName":"진","imageId":"Jhin","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"진은 살인이 예술이라고 믿는 주도면밀한 사이코패스 살인범이다. 원래는 아이오니아의 감옥에 수감되어 있었는데, 아이오니아 평의회 내에서 암약하는 어두운 세력의 힘으로 풀려난 이후 그 파벌의 자객으로 일하고 있다. 진은 총을 붓 삼아 잔혹한 그림을 그리는 화가이자, 소름끼치는 작품을 무대에 올리며 쾌락을 느끼는 극작가다. 그 솜씨를 접하는 피해자와 목격자들은 모두 얼어붙을 수밖에 없다. 누군가에게 \'공포\'라는 강렬한 메시지를 전하고 싶다면, 진이야말로...","tags":["원거리","마법사"]},{"name":"Jinx","koreanName":"징크스","imageId":"Jinx","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"보통","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"지하도시 출신의 충동적이고 불안정한 범죄자 징크스는 자신의 과거가 빚어낸 결과에 시달리면서도 필트오버와 자운에 특유의 대혼란을 일으키는 것을 멈추지 않는다. 손수 만든 무기를 파괴적으로 사용해 화려한 폭발과 총격을 쏟아내며 가는 곳마다 쑥대밭을 만들어 소외된 자들을 반란과 저항으로 이끈다.","tags":["원거리"]},{"name":"Kaisa","koreanName":"카이사","imageId":"Kaisa","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"카이사는 어린아이에 불과했을 때 공허에 끌려들어 갔지만 불굴의 의지와 집요한 노력 끝에 간신히 살아남을 수 있었다. 이때의 경험으로 카이사는 치명적인 위력의 사냥꾼이 되었다. 어떤 이들에게는 차라리 죽어서 보지 않는 게 나을 정도로 끔찍한 미래를 암시하는 징조로 여겨지기도 한다. 카이사는 이제 그녀의 두 번째 피부가 된 공허충의 껍질을 덮어쓰고 불유쾌한 공생 관계를 유지해야 하는 것은 물론, 머지않은 미래에 결단을 내려야만 한다. 자신을 괴물이라고...","tags":["원거리","마법사"]},{"name":"Kalista","koreanName":"칼리스타","imageId":"Kalista","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"보통","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"칼리스타, 영원불멸하는 복수의 화신이자 분노에 찬 응징의 혼. 그림자 군도에서 소환되는 칼리스타는 배신자와 반역자들에겐 악몽이 그 자체로 갑옷을 두르고 현실화한 듯한 존재이다. 배신당한 이들이 피맺힌 외침으로 복수를 갈망할 때, 영혼도 기꺼이 내놓겠다는 자들에겐 칼리스타의 응답이 들린다. 그 분노의 표적이 된 자는 결코 무사할 수 없다. 칼리스타는 무자비한 추격자이며, 복수의 계약을 끝낼 수 있는 것은 영혼을 꿰뚫는 창날의 차가운 불꽃뿐이기 때문이다.","tags":["원거리"]},{"name":"Caitlyn","koreanName":"케이틀린","imageId":"Caitlyn","positions":["원딜"],"riotClass":"원거리","riotSubClass":null,"difficulty":"보통","style":["원거리"],"gameStyle":"control","visual":[],"setting":[],"description":"필트오버 제일가는 평화 수호자로 명성이 자자한 케이틀린 키라먼은 이 도시에서 가장 뛰어난 명사수이기도 하다. 그 잡기 어렵다는 필트오버의 범죄 조직들도 그녀의 손에 소탕되었다. 케이틀린은 주로 바이와 짝을 이루어, 바이의 불같은 성미를 자신의 냉철함으로 보완하며 멋진 콤비로 활약한다. 케이틀린의 마법공학 소총이 독보적으로 우수한 성능인 것은 사실이지만, 정작 케이틀린의 가장 강력한 무기는 따로 있다. 필트오버에서 활개 칠 생각을 할 정도로 무모한...","tags":["원거리"]},{"name":"Kog\'Maw","koreanName":"코그모","imageId":"KogMaw","positions":["원딜"],"riotClass":"원거리","riotSubClass":"마법사","difficulty":"보통","style":["원거리","마법사"],"gameStyle":"control","visual":[],"setting":[],"description":"이케시아의 황무지 어딘가, 인간의 눈길이 닿지 않는 깊은 곳에 공허의 틈이 나타났고, 썩은 내를 풍기는 이곳에서 코그모가 느닷없이 튀어나왔다. 온몸에서는 악취가 스며나오고, 호기심 때문에 항상 떡 벌리고 있는 입에서는 부식성 분비물이 뚝뚝 떨어진다. 주변에 있는 건 닥치는 대로 마구 물어뜯고 침을 질질 흘린 후에야 그것이 무엇인지 알아차린다. 공허태생이지만 천성이 악하지는 않고 천진난만한 언행에 묘한 매력도 있지만, 방심은 금물이다. 식탐과 호기심이...","tags":["원거리","마법사"]},{"name":"Tristana","koreanName":"트리스타나","imageId":"Tristana","positions":["원딜"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"쉬움","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"다른 많은 요들이 발견, 발명, 또는 그저 장난에 기력을 쏟지만, 트리스타나는 언제나 위대한 전사가 되기 위해 모험을 떠나는 꿈을 꿨다. 트리스타나는 룬테라, 룬테라의 파벌, 그리고 전쟁 이야기를 즐겨 들었고, 요들도 얼마든지 전설이 될 수 있다고 생각했다. 트리스타나는 이제 세계에 첫 발을 내딛으며, 든든한 대포 \'부머\'를 들고 변함없는 용기와 낙관적인 성격으로 전장에 뛰어 든다.","tags":["원거리","암살자","입문추천"]},{"name":"Twitch","koreanName":"트위치","imageId":"Twitch","positions":["원딜"],"riotClass":"원거리","riotSubClass":"암살자","difficulty":"보통","style":["원거리","암살자"],"gameStyle":"control","visual":[],"setting":[],"description":"자운에서 전염병을 옮기는 쥐로 태어난 트위치는 열정적인 오물 전문가로, 앞발을 더럽히는 것을 두려워하지 않는다. 트위치는 필트오버의 부유층을 향해 화학물질로 강화한 석궁을 겨누며, 지상의 인간들의 더러움을 적나라하게 드러내기로 다짐했다. 지하동굴에 웅크리고 있을 때를 제외하면 늘 비밀스럽게 교활한 움직임을 일삼는 트위치는 버려진 보물을 찾아 쓰레기 더미를 뒤지고 있다. 곰팡이 슨 샌드위치라도 찾을 수 있을까 하며.","tags":["원거리","암살자"]}],"서포터":[{"name":"Nami","koreanName":"나미","imageId":"Nami","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"나미는 바다에 사는 바스타야 종족으로, 어리지만 완고할 정도로 고집이 세다. 먼 옛날 타곤 인과 맺었던 약속이 깨지자, 마라이 종족으로는 처음으로 파도 치는 바다에서 나와 마른 육지로 모험을 떠났다. 달리 해결책이 없었기에, 자신의 종족을 안전하게 지켜주는 성스러운 의식을 완수한다는 임무를 자청한 것이었다. 새로운 시대는 혼란 그 자체지만, 나미는 용기와 결단력으로 불확실한 미래를 마주한다. 그녀의 무기는 바다의 힘을 소환하는 파도 소환사의 지팡이다.","tags":["서포터","마법사","입문추천"]},{"name":"Nautilus","koreanName":"노틸러스","imageId":"Nautilus","positions":["서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"보통","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"빌지워터에는 처음으로 물에 잠긴 부두만큼이나 오래되었다는 쓸쓸한 전설이 하나 있다. 육중한 갑옷을 걸친 노틸러스라는 이름의 거인이 푸른 불꽃 제도 해안가의 검푸른 물을 배회한다는 이야기이다. 이제는 기억나지도 않을 복수심에 사로잡힌 그는 예고도 없이 거대한 닻을 휘둘러 가여운 자들을 구하고 탐욕스러운 자들을 죽음으로 인도한다. \'빌지워터의 공물\'이라는 절대 어겨선 안 될 약속을 잊은 자들을 바닷속으로 끌고 들어가며, 끌려들어 간 자는 누구도 그곳에서...","tags":["탱커","서포터"]},{"name":"Rakan","koreanName":"라칸","imageId":"Rakan","positions":["서포터"],"riotClass":"서포터","riotSubClass":null,"difficulty":"쉬움","style":["서포터"],"gameStyle":"support","visual":[],"setting":[],"description":"활달하고 변덕스러우면서도 거부하기 힘든 매혹을 발산하는 라칸은 악명 높은 바스타야 말썽꾼이자 로틀란 부족 역사상 가장 훌륭한 전장의 춤꾼이다. 아이오니아 고원 지대에 사는 사람들에게 라칸이라는 이름은 꽤 오래 전부터 시끌벅적한 축제, 흥이 넘치는 파티, 기존의 규칙을 거부하는 음악과 동일시되고 있다. 하지만 타고난 춤꾼이자 활력 넘치는 방랑자인 라칸이 저항 운동을 하는 자야와 동반자 관계가 되었으며, 자야의 대의에 헌신하고 있다는 사실을 아는 사람은...","tags":["서포터","입문추천"]},{"name":"Renata","koreanName":"레나타 글라스크","imageId":"Renata","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"어려움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"레나타 글라스크는 어린 시절 집의 잿더미를 딛고 일어섰다. 그때 레나타가 가진 것은 이름과 부모님의 연금술 연구 자료뿐이었다. 수십 년이 지나, 레나타는 자운에서 가장 부유한 화공 남작 겸 거물 사업가가 되었다. 그녀는 모든 사람의 이해관계를 자신과 묶어서 막대한 힘을 쌓았다. 레나타와 함께하는 자는 상상 이상의 보상을 받는다. 레나타를 거스르는 자는 그 선택을 후회하며 살아간다. 하지만 결국에는 모두가 그녀의 편에 설 것이다.","tags":["서포터","마법사","고난이도"]},{"name":"Leona","koreanName":"레오나","imageId":"Leona","positions":["서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"솔라리 성전사 레오나는 천공의 검과 여명의 방패로 타곤 산을 수호한다. 레오나의 몸은 태양의 불길로 가득하며, 피부는 별의 광채로 빛나고, 눈동자는 천체들의 기운으로 불타오른다. 황금 갑주와 어마어마한 고대의 지식으로 무장한 레오나는 어떤 이들에게는 깨우침을, 어떤 이들에게는 죽음을 선사한다.","tags":["탱커","서포터","입문추천"]},{"name":"Rell","koreanName":"렐","imageId":"Rell","positions":["서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"검은 장미단의 악랄한 실험으로 탄생한 렐은 녹서스의 전복만을 위해 달리는 생체 무기이다. 금속을 조종하는 능력 때문에 그녀는 고통과 공포로 점철된 어린 시절을 보내며 끔찍한 전투 훈련을 받아야 했다. 견디다 못한 나머지 자신을 구속한 자들을 죽이고 도망쳤고, 결국 범죄자로 낙인찍혔다. 자유의 몸이 된 렐은 이제 자신과 같은 고통을 겪던 아이들을 구출하며 녹서스 병사들을 보이는 대로 처치한다. 그리고 과거의 스승들에게는 무자비한 죽음을 안겨 주고...","tags":["탱커","서포터","입문추천"]},{"name":"Lulu","koreanName":"룰루","imageId":"Lulu","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"요들 마법사 룰루는 친구인 요정 픽스와 함께 룬테라를 돌아다니며, 꿈결같은 환상과 상상 속에서나 존재할 법한 생명체를 만들어내는 것으로 유명하다. 룰루는 내키는 대로 현실을 빚어내고, 세상의 법칙을 비틀어 버린다. 룰루가 보기에 이 세상의 물리 법칙에 따르는 제약은 시시하고 따분하다. 룰루의 마법은 좋게 본다 해도 비정상적이고 나쁘게 보면 위험하다고까지 할 수도 있겠지만, 룰루의 신념은 확고하다. 사람들에게 마법 한 번씩 맛보여 주는 게 뭐 그리...","tags":["서포터","마법사","입문추천"]},{"name":"Maokai","koreanName":"마오카이","imageId":"Maokai","positions":["서포터","탑"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"매우 쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"거대한 나무 정령 마오카이는 분노에 휩싸여 그림자 군도의 초자연적인 언데드와 싸운다. 마법에 의한 대격변으로 고향이 파괴되었을 때 그는 자신의 나무 심장에 스며 있는 생명의 정수로 언데드의 상태는 모면했지만 형체가 뒤틀린 복수의 화신이 되었다. 한 때는 평화를 사랑하는 자연의 정령이었으나 이제 그는 그림자 군도를 뒤덮은 언데드를 몰아내고 아름답던 고향의 옛 모습을 되찾기 위해 맹렬하게 싸운다.","tags":["탱커","서포터","입문추천","멀티포지션"]},{"name":"Morgana","koreanName":"모르가나","imageId":"Morgana","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"매우 쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"천상의 힘과 필멸의 육신 사이에서 고뇌하던 모르가나는 자신의 날개를 묶고 다시 인간의 삶을 살면서 부정하고 타락한 자들을 벌한다. 그녀는 데마시아의 부당한 법과 전통을 거부하며, 왕국의 그림자 속에서 암흑 불꽃으로 만든 방패와 사슬로 진실을 억압하려는 자들에 맞서 싸운다. 추방당하고 버림받은 자라고 해도 언젠가 다시 돌아올 수 있다고 믿기 때문이다.","tags":["서포터","마법사","입문추천"]},{"name":"Milio","koreanName":"밀리오","imageId":"Milio","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"밀리오는 이쉬탈 출신의 마음 따뜻한 소년으로, 어린 나이에 불의 액시옴을 숙달하고 \'치유의 불꽃\'이라는 새로운 능력을 발견했다. 그리고 자신의 할머니가 그랬듯, 이 새로운 능력을 활용해 윤 탈에 들어가서 가족의 옛 영광을 되찾으려고 한다. 이쉬탈 전역의 정글을 여행하며 결국 수도 이샤오칸에 도착한 밀리오는 윤 탈에 들어가기 위해 비달리온을 준비한다. 어떤 고난과 위험이 자신을 기다리는지 모르는 채로.","tags":["서포터","마법사","입문추천"]},{"name":"Bard","koreanName":"바드","imageId":"Bard","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"어려움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"별 너머에서 온 여행자 바드는 뜻밖의 발견과 예기치 않은 행운을 수호하며, 삶이 무심한 혼돈을 견딜 수 있도록 우주의 균형을 유지하기 위해 싸운다. 룬테라 인들은 바드가 신비하고 초월자적인 존재라는 내용의 노래를 곧잘 흥얼거리지만, 이 우주의 방랑자가 강력한 마법의 힘이 깃든 유물에 집착한다는 사실은 모든 룬테라 인이 동의하는 바다. 하지만 유익한 정령들이 내는 환희 어린 합창에 둘러싸인 바드가 악의를 지니고 있는 것은 아닐 터이다. 바드는 필멸의...","tags":["서포터","마법사","고난이도"]},{"name":"Vel\'Koz","koreanName":"벨코즈","imageId":"Velkoz","positions":["서포터","미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"어려움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"벨코즈가 룬테라에 나타난 첫 번째 공허태생인지는 확실하지 않다. 다만 벨코즈만큼 잔혹하면서 계산적인 지성체는 이제껏 존재하지 않았다. 다른 공허태생들은 주변의 모든 것을 닥치는 대로 집어삼키고 부패시키지만, 벨코즈는 현실 세계뿐 아니라 현실 세계에 사는 호전적이고 낯선 생명체들을 자세히 관찰하고 연구하여 공허가 이용할 수 있는 약점을 찾아낸다. 그렇다고 벨코즈가 그저 수동적인 관찰자라는 말은 아니다. 위협을 느끼면 치명적인 플라즈마 광선을 발사하거나...","tags":["마법사","서포터","고난이도","멀티포지션"]},{"name":"Braum","koreanName":"브라움","imageId":"Braum","positions":["서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"매우 쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"축복받은 거대 이두박근과 그보다도 더 크고 호방한 마음을 지닌 브라움은 프렐요드 주민들이 사랑해 마지않는 영웅이다. 프로스텔드 북방에서 연회가 열리면 빠지지 않는 순서가 바로 브라움의 팔힘에 건배를 하는 것이다. 전설에 따르면 브라움은 단 하룻밤에 오크나무 숲 전체를 베어버렸고, 산 하나를 주먹으로 부수어 돌무더기로 만들어 버렸다고 한다. 마법이 깃든 동굴 문짝을 방패 삼아 들고, 근육만큼이나 커다란 콧수염 아래 사람 좋은 미소를 활짝 띤 브라움은...","tags":["탱커","서포터","입문추천"]},{"name":"Brand","koreanName":"브랜드","imageId":"Brand","positions":["서포터","미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"쉬움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"케간 로디는 얼음이 뒤덮인 프렐요드의 어느 부족민이었으나 거대한 힘의 유혹에 넘어가 브랜드가 되었다. 전설처럼 전해지는 세계 룬 중 하나를 찾아나선 그는 막판에 동료들을 배신하고 세계 룬을 혼자 차지했다. 그리고 다음 순간, 케간 로디는 더 이상 존재하지 않았다. 영혼은 불에 타 사라지고, 육신은 살아 있는 화염에 휩싸여 브랜드가 되어버린 것이다. 브랜드는 이제 또 다른 세계 룬을 찾아 발로란을 헤매며, 필멸자는 십여 번을 다시 태어나 산다 해도...","tags":["마법사","서포터","입문추천","멀티포지션"]},{"name":"Blitzcrank","koreanName":"블리츠크랭크","imageId":"Blitzcrank","positions":["서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"블리츠크랭크는 지하도시 자운의 기술이 만들어낸 거대한 기계로 사실상 파괴불가능에 가깝다. 원래는 자운을 뒤덮은 유독 폐기물을 처리하기 위해 만들어진 골렘이었으나, 연약하기 짝이 없는 자운 시민들을 지키기 위해서는 폐기물을 치우는 것만으로는 모자란다고 판단하여 스스로 형체를 변형시키기에 이르렀다. 블리츠크랭크는 골렘다운 힘과 내구성을 사심 없이 활용하여 사람들을 보호하고, 말썽꾼이 눈에 띄면 강철 주먹을 내지르거나 에너지를 분출하여 진압한다.","tags":["탱커","서포터","입문추천"]},{"name":"Senna","koreanName":"세나","imageId":"Senna","positions":["서포터","원딜"],"riotClass":"서포터","riotSubClass":"원거리","difficulty":"보통","style":["서포터","원거리"],"gameStyle":"support","visual":[],"setting":[],"description":"어린 시절부터 초자연적인 검은 안개에 쫓기는 저주를 받은 세나는 빛의 감시자들이라는 신성한 조직에 합류하여 검은 안개에 맹렬히 저항하지만, 잔혹한 악령 쓰레쉬의 손에 쓰러지고 랜턴에 영혼을 사로잡히게 된다. 그러나 희망을 잃지 않은 그녀는 랜턴 안에서 안개의 힘을 활용하는 법을 배워 완전히 새로운 모습으로 다시 태어난다. 제 빛과 어둠을 모두 다스릴 수 있게 된 세나는 검은 안개를 자멸케 하고자 한다. 세나의 유물 무기가 불을 뿜을 때마다, 검은...","tags":["서포터","원거리","멀티포지션"]},{"name":"Seraphine","koreanName":"세라핀","imageId":"Seraphine","positions":["서포터","미드"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"자운 출신의 부모를 둔 세라핀은 필트오버에서 태어나 다른 사람의 영혼의 소리를 들을 수 있다. 세상이 그녀에게 노래하고 그녀 또한 답가를 불렀다. 어린 시절에는 이 소리가 그녀를 억눌렀지만 이제 그녀는 영감을 위해 소리를 이끌어내고 혼돈을 협화음으로 바꿀 수 있게 되었다. 세라핀은 두 도시를 위해 공연하며 시민들에게 그들은 혼자가 아니고 함께일 때 더 강하며, 그들의 잠재력은 무한하다는 것을 일깨워준다.","tags":["서포터","마법사","입문추천","멀티포지션"]},{"name":"Sona","koreanName":"소나","imageId":"Sona","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"소나는 현악기 에트왈 연주에서 데마시아 제일가는 거장으로, 말을 하지 못하며 오로지 우아한 화음과 심금을 울리는 아리아로만 의사를 표현한다. 특유의 고상한 몸가짐 때문에 데마시아 상류층의 사랑을 받지만, 듣는 이의 마음을 사로잡는 소나의 선율이 실제로 마법이 아닌가 의심하는 사람들도 많다. 알다시피 마법은 데마시아에서 금기시되고 있기 때문이다. 소나는 낯선 이들에게 침묵을 지키지만, 가까운 지인들은 그녀의 의사를 어느 정도 이해한다. 소나가 연주하는...","tags":["서포터","마법사","입문추천"]},{"name":"Soraka","koreanName":"소라카","imageId":"Soraka","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"매우 쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"타곤 산 너머 천상계의 방랑자 소라카는 필멸자들이 스스로의 폭력성 때문에 고통받는 것을 치유하기 위해 자신의 불멸을 포기했다. 소라카는 만나는 모든 이에게 동정심과 자비의 마음을 심어주려고 노력하며, 심지어 자신에게 해를 입히려 획책하는 자들마저 치유한다. 이 세계의 갈등과 혼란을 모두 지켜보았음에도, 소라카는 아직 룬테라 인들이 잠재력을 모두 끌어낸 것은 아니라고 믿고 있다.","tags":["서포터","마법사","입문추천"]},{"name":"Swain","koreanName":"스웨인","imageId":"Swain","positions":["서포터","미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"어려움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"제리코 스웨인은 오로지 힘만을 숭상하는 확장주의 국가 녹서스를 탁월한 예지력으로 이끄는 지도자다. 아이오니아 전쟁에서 부상을 당해 절름발이가 되고 왼팔을 잃었지만, 가차 없는 결단력으로 제국을 통치하는 자리에까지 올랐다. 악마에게 새로이 받은 왼팔과, 그 못지않게 악마 같은 수를 써서… 이제 스웨인은 최전선에서 군을 지휘하며 자신만이 볼 수 있는 어둠, 주변에 흩어진 시체에 몰려든 새까만 까마귀들에서 얼핏얼핏 목격한 광경이 다가오는 것에 대비하고...","tags":["마법사","서포터","고난이도","멀티포지션"]},{"name":"Thresh","koreanName":"쓰레쉬","imageId":"Thresh","positions":["서포터"],"riotClass":"서포터","riotSubClass":"탱커","difficulty":"보통","style":["서포터","탱커"],"gameStyle":"support","visual":[],"setting":[],"description":"가학적이고 교활한 그림자 군도의 악령인 쓰레쉬는 이 세계에 고통을 전파하겠다는 야심을 품고 잠시도 쉬지 않는다. 원래는 신비로운 비밀이 가득한 지하 창고의 관리인이었으나, 삶이나 죽음보다 더 거대한 힘에 의해 타락했고 이제는 기발한 고문 방법을 생각해 내어 사람들을 괴롭히며, 오랫동안 견디기 힘든 고통을 가하여 서서히 망가뜨리는 일에 심취하고 있다. 쓰레쉬의 마수에 붙잡힌 자는 죽음으로도 그 손아귀를 벗어날 수 없다. 쓰레쉬가 랜턴에 영혼을 가두고는...","tags":["서포터","탱커"]},{"name":"Alistar","koreanName":"알리스타","imageId":"Alistar","positions":["서포터"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"보통","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"비할 데 없이 강력한 전사라는 평판이 자자한 알리스타는 녹서스 제국에게 부족 전체가 몰살당한 이래 그 복수를 꿈꾸고 있다. 노예로 잡힌 후 참혹한 전투를 거듭해야 하는 검투사 신세가 되었으나, 그 누구도 꺾을 수 없는 의지가 있어 마음 깊은 곳까지 야수로 변하지는 않았다. 알리스타는 노예라는 구속에서 벗어나 자유의 몸이 된 후에도 탄압당하고 기댈 곳 없는 자들을 위해 싸우고 있다. 알리스타의 분노는 그의 뿔이나 발굽, 주먹 못지 않게 적들이...","tags":["탱커","서포터"]},{"name":"Yuumi","koreanName":"유미","imageId":"Yuumi","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"매우 쉬움","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"유미는 밴들 시티 출신의 마법 고양이로 한때 요들 마법사 노라와 함께 살았다. 어느 날 노라가 알 수 없는 이유로 종적을 감추자 유미는 자아를 지닌 노라의 책 \'관문의 서\'의 수호자가 되었으며, 책 페이지 안에 존재하는 차원문을 타고 주인을 찾는 여정에 나섰다. 애정을 갈구하는 유미는 여정을 함께 떠날 친절한 동료들을 구하며, 빛나는 방패와 단호한 결의로 그들을 보호한다. 노라의 책은 유미가 눈앞에 놓인 임무에 집중하도록 하기 위해 애쓰지만, 유미는...","tags":["서포터","마법사","입문추천"]},{"name":"Zyra","koreanName":"자이라","imageId":"Zyra","positions":["서포터"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"보통","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"자이라는 고대의 어떤 마법 대재앙에서 태어났다. 자연의 분노가 그대로 형상화된 생명체이자 인간과 식물의 매혹적인 혼종이다. 자이라가 한 걸음 내디딜 때마다 발밑에는 새로운 생명이 피어난다. 발로란의 수많은 필멸자를 자신의 씨앗에서 태어난 후손의 먹잇감 정도로 여기므로, 치명적인 위력의 가시를 날려 필멸자를 거침없이 사냥한다. 또한 자이라는 발로란 여기저기에 식육 식물 군락을 만들어 놓는데, 이 군락은 주변의 다른 생명체를 모조리 휘감아 죽이며 세력을...","tags":["마법사","서포터"]},{"name":"Janna","koreanName":"잔나","imageId":"Janna","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"보통","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"룬테라의 돌풍이라는 강력한 무기를 지닌, 그러나 모든 것이 베일에 싸인 잔나. 그녀는 이제 폐허가 되어버린 자운을 지키는 바람의 정령이다. 그런 그녀를 두고 떠도는 이야기는 많다. 그중에서 가장 그럴듯한 설은 바로 수호신으로서의 잔나. 악천후 속에서 폭풍우를 뚫고 나아가며 부디 순항할 수 있기를 기원하는 룬테라 선원들의 간구 속에서 등장했다고 여기는 것이다. 사람들은 잔나가 남다른 애정으로 자운의 선원들을 보호한다고 믿었다. 잔나와 자운, 이 둘의...","tags":["서포터","마법사"]},{"name":"Xerath","koreanName":"제라스","imageId":"Xerath","positions":["서포터","미드"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"어려움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"고대 슈리마의 초월한 마법사 제라스는 신비의 에너지가 석관의 파편에 둘러싸인 형상을 하고 있다. 그는 사막 아래의 고대 감옥 속에 수천 년 동안 갇혀 있다가 슈리마 제국의 부활과 함께 자유의 몸이 되었다. 막강한 힘을 손에 넣은 제라스는 응당 자신의 것이라 여기는 것들을 찬탈하고 신흥 문명 정복으로 자신만의 제국을 세우고자 광기의 질주를 시작한다.","tags":["마법사","서포터","고난이도","멀티포지션"]},{"name":"Zilean","koreanName":"질리언","imageId":"Zilean","positions":["서포터"],"riotClass":"서포터","riotSubClass":"마법사","difficulty":"보통","style":["서포터","마법사"],"gameStyle":"support","visual":[],"setting":[],"description":"한때 이케시아의 강력한 마법사였던 질리언은 자신의 고국이 공허에 파괴되는 것을 목격한 후 시간의 흐름에 사로잡히게 되었다. 질리언은 처참한 상실감에 슬퍼할 틈도 없이, 미래의 모든 경우의 수를 예측하기 위해 시간 마법의 주문을 외웠다. 이제 사실상 불멸의 몸이 된 질리언은 과거, 현재, 미래를 표류하며 주변 시간의 흐름을 구부리거나 왜곡하여 시간을 되감고 있다. 이케시아를 멸망하기 전으로 돌려 놓을 시점을 찾아 모든 시간대에서 망연히 부유하는 것이다.","tags":["서포터","마법사"]},{"name":"Karma","koreanName":"카르마","imageId":"Karma","positions":["서포터"],"riotClass":"마법사","riotSubClass":"서포터","difficulty":"쉬움","style":["마법사","서포터"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"아이오니아의 영적인 전통을 카르마보다 잘 나타내는 필멸자가 있을까. 카르마는 지난 시간 동안 축적된 기억을 새로운 생명으로 온존하며 수없이 부활한 고대 영혼의 살아있는 현신으로, 극소수만이 깨우칠 수 있는 힘을 손에 넣었다. 최근 위기가 닥쳤을 때 최선을 다해 자신을 따르는 이들을 이끈 카르마는 자신과 자신이 그토록 아끼는 조국 모두가 상당한 대가를 치러야만 평화와 조화가 찾아오리라는 것을 알고 있다.","tags":["마법사","서포터","입문추천"]},{"name":"Taric","koreanName":"타릭","imageId":"Taric","positions":["서포터"],"riotClass":"서포터","riotSubClass":"탱커","difficulty":"매우 쉬움","style":["서포터","탱커"],"gameStyle":"support","visual":[],"setting":[],"description":"타릭은 초월적인 힘으로 룬테라의 생명과 사랑, 아름다움을 수호하는 수호자의 성위이다. 고국 데마시아에서 직무태만죄를 범하고 수치스럽게 추방당한 타릭은 속죄를 위해 타곤 산을 올랐고, 이 산 정상에서 하늘의 별들에게 더 큰 소명을 부여받았다. 고대 타곤의 신비한 힘을 가득 받아 끔찍한 공허의 침식으로부터 밤낮없이 세계를 지키는 발로란의 방패가 된 것이다.","tags":["서포터","탱커","입문추천"]},{"name":"Tahm Kench","koreanName":"탐 켄치","imageId":"TahmKench","positions":["서포터","탑"],"riotClass":"탱커","riotSubClass":"서포터","difficulty":"쉬움","style":["탱커","서포터"],"gameStyle":"defensive","visual":[],"setting":[],"description":"역사 속에서 여러 이름으로 알려져 있는 악마 탐 켄치는 룬테라의 물길을 따라 이동하며 끝없는 식욕을 다른 이들의 고통으로 채운다. 탐 켄치를 매우 매력적이고 자신만만한 존재로 생각하는 이들도 있지만, 탐 켄치는 방심한 먹잇감을 찾아 현실 세계를 활보하는 방랑자일 뿐이다. 탐 켄치의 채찍 같은 혓바닥은 수십 걸음 떨어진 중무장한 전사도 기절시킬 수 있으며, 탐 켄치의 꾸르륵대는 뱃속으로 들어가는 것은 다시 돌아올 희망이 거의 없는 심연에 떨어지는...","tags":["탱커","서포터","입문추천","멀티포지션"]},{"name":"Pyke","koreanName":"파이크","imageId":"Pyke","positions":["서포터"],"riotClass":"서포터","riotSubClass":"암살자","difficulty":"보통","style":["서포터","암살자"],"gameStyle":"support","visual":[],"setting":[],"description":"빌지워터 학살의 부두에서 유명한 작살잡이였던 파이크는 거대한 자울치의 뱃속에서 죽음을 맞이할 운명이었지만... 살아 돌아왔다. 이제, 그는 옛 고향의 음습한 골목과 뒷길을 소리 없이 누비며, 타인을 이용하여 부를 쌓은 자들에게 그가 얻은 초자연적인 힘으로 빠르고 잔혹한 최후를 선사한다. 괴물을 사냥한다고 자부했던 도시는 이제 괴물에게 사냥당하고 있다.","tags":["서포터","암살자"]},{"name":"Pantheon","koreanName":"판테온","imageId":"Pantheon","positions":["서포터","탑"],"riotClass":"전사","riotSubClass":"암살자","difficulty":"쉬움","style":["전사","암살자"],"gameStyle":"aggressive","visual":[],"setting":[],"description":"본의 아니게 전쟁의 성위에 잠식된 아트레우스는 자신에게 깃든 천상의 힘을 파괴하고 하늘의 별을 사라지게 할 정도로 강력한 일격에도 굴복하지 않고 살아남았다. 그리고 결국 필멸의 운명을 인정하고, 그에 따르는 힘과 불굴의 정신을 받아들였다. 이제 아트레우스는 신성에 저항하는 판테온으로 다시 태어나, 꺾이지 않는 의지와 성위의 무기로 무장한 채 전장을 누빈다.","tags":["전사","암살자","입문추천","멀티포지션"]}]}');

